s($,"aQ2","ar4",()=>A.b([A.asZ(A.b([A.anO("\u0936\u0941\u092d\u093e\u0936\u0941\u092d\u092a\u094d\u0930\u0915\u0930\u0923\u092e\u094d","Shubhashubha Prakaranam","mc_ch1","\u0cb6\u0cc1\u0cad\u0cbe\u0cb6\u0cc1\u0cad \u0caa\u0ccd\u0cb0\u0c95\u0cb0\u0ca3 (\u0ce7-\u0ce8\u0ce6)",1,A.b([A.aM("\u092a\u094d\u0930\u0923\u092e\u094d\u092f \u0939\u0947\u0930\u092e\u094d\u092c\u092e\u0936\u0947\u0937\u0935\u093f\u0918\u094d\u0928-\u0935\u093f\u0928\u093e\u0936\u093f\u0928\u0902 \u092d\u093e\u0938\u094d\u0915\u0930\u092e\u093f\u0937\u094d\u091f\u0926\u0902 \u091a \u0964\n\u092e\u0941\u0939\u0942\u0930\u094d\u0924\u091a\u093f\u0928\u094d\u0924\u093e\u092e\u0923\u093f\u092e\u093e\u0924\u0928\u094b\u0924\u093f \u0936\u094d\u0930\u0940\u0930\u093e\u092e\u0926\u0948\u0935\u091c\u094d\u091e\u0935\u0930\u0903 \u0936\u0941\u092d\u093e\u0930\u094d\u0925\u092e\u094d \u0965 \u0967 \u0965","mc_1_1","\u0cb8\u0cae\u0cb8\u0ccd\u0ca4 \u0cb5\u0cbf\u0c98\u0ccd\u0ca8\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca8\u0cbe\u0cb6\u0cae\u0cbe\u0ca1\u0cc1\u0cb5 \u0cb5\u0cbf\u0ca8\u0cbe\u0caf\u0c95\u0ca8\u0ca8\u0ccd\u0ca8\u0cc2 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c87\u0cb7\u0ccd\u0c9f\u0cbe\u0cb0\u0ccd\u0ca5\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca6\u0caf\u0caa\u0cbe\u0cb2\u0cbf\u0cb8\u0cc1\u0cb5 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca6\u0cc7\u0cb5\u0ca8\u0ca8\u0ccd\u0ca8\u0cc2 \u0ca8\u0cae\u0cb8\u0ccd\u0c95\u0cb0\u0cbf\u0cb8\u0cbf, \u0cb6\u0ccd\u0cb0\u0cc7\u0cb7\u0ccd\u0ca0 \u0c9c\u0ccd\u0caf\u0ccb\u0ca4\u0cbf\u0cb7\u0cbf\u0caf\u0cbe\u0ca6 \u0cb6\u0ccd\u0cb0\u0cc0\u0cb0\u0cbe\u0cae \u0ca6\u0cc8\u0cb5\u0c9c\u0ccd\u0c9e\u0cb0\u0cc1 \u0c9c\u0ca8\u0cb0 \u0c95\u0cb2\u0ccd\u0caf\u0cbe\u0ca3\u0c95\u0ccd\u0c95\u0cbe\u0c97\u0cbf (\u0cb6\u0cc1\u0cad\u0cbe\u0cb0\u0ccd\u0ca5\u0cb5\u0cbe\u0c97\u0cbf) \u0c88 '\u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4 \u0c9a\u0cbf\u0c82\u0ca4\u0cbe\u0cae\u0ca3\u0cbf' \u0c8e\u0c82\u0cac \u0c97\u0ccd\u0cb0\u0c82\u0ca5\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb5\u0cbf\u0cb8\u0ccd\u0ca4\u0cb0\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0cbf\u0ca6\u0ccd\u0ca6\u0cbe\u0cb0\u0cc6.","\u0caa\u0ccd\u0cb0\u0ca3\u0cae\u0ccd\u0caf \u0cb9\u0cc7\u0cb0\u0c82\u0cac\u0cae\u0cb6\u0cc7\u0cb7\u0cb5\u0cbf\u0c98\u0ccd\u0ca8-\u0cb5\u0cbf\u0ca8\u0cbe\u0cb6\u0cbf\u0ca8\u0c82 \u0cad\u0cbe\u0cb8\u0ccd\u0c95\u0cb0\u0cae\u0cbf\u0cb7\u0ccd\u0c9f\u0ca6\u0c82 \u0c9a \u0964\n\u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4\u0c9a\u0cbf\u0c82\u0ca4\u0cbe\u0cae\u0ca3\u0cbf\u0cae\u0cbe\u0ca4\u0ca8\u0ccb\u0ca4\u0cbf \u0cb6\u0ccd\u0cb0\u0cc0\u0cb0\u0cbe\u0cae\u0ca6\u0cc8\u0cb5\u0c9c\u0ccd\u0c9e\u0cb5\u0cb0\u0c83 \u0cb6\u0cc1\u0cad\u0cbe\u0cb0\u0ccd\u0ca5\u0cae\u0ccd \u0965 \u0ce7 \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0caa\u0cc0\u0caf\u0cc2\u0cb7\u0ca7\u0cbe\u0cb0\u0cbe & \u0cb0\u0cb9\u0cb8\u0ccd\u0caf\u0cbe\u0cb0\u0ccd\u0ca5): \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca8\u0cbf\u0cb0\u0ccd\u0cb5\u0cbf\u0c98\u0ccd\u0ca8\u0cb5\u0cbe\u0c97\u0cbf \u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0c97\u0cca\u0cb3\u0cbf\u0cb8\u0cb2\u0cc1 \u0cb5\u0cbf\u0c98\u0ccd\u0ca8\u0c97\u0cb3 \u0ca8\u0cbf\u0caf\u0c82\u0ca4\u0ccd\u0cb0\u0c95\u0ca8\u0cbe\u0ca6 \u0c97\u0ca3\u0caa\u0ca4\u0cbf\u0caf \u0cb8\u0ccd\u0cae\u0cb0\u0ca3\u0cc6 \u0c85\u0ca4\u0ccd\u0caf\u0c97\u0ca4\u0ccd\u0caf. \u0c9c\u0ccd\u0caf\u0ccb\u0ca4\u0cbf\u0cb7 \u0cb6\u0cbe\u0cb8\u0ccd\u0ca4\u0ccd\u0cb0\u0cb5\u0cc1 \u0cb5\u0cc7\u0ca6\u0ca6 \u0c95\u0ca3\u0ccd\u0ca3\u0cbe\u0c97\u0cbf\u0cb0\u0cc1\u0cb5\u0cc1\u0ca6\u0cb0\u0cbf\u0c82\u0ca6, \u0c95\u0cbe\u0cb2\u0ca6 \u0ca8\u0cbf\u0caf\u0c82\u0ca4\u0ccd\u0cb0\u0c95\u0ca8\u0cc2 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0ca8\u0cb5\u0c97\u0ccd\u0cb0\u0cb9\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0cae\u0cc2\u0cb2\u0c95\u0cbe\u0cb0\u0ca3\u0ca8\u0cc2 \u0c86\u0ca6 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb8\u0ccd\u0ca4\u0cc1\u0ca4\u0cbf\u0cb8\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6. '\u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4 \u0c9a\u0cbf\u0c82\u0ca4\u0cbe\u0cae\u0ca3\u0cbf' \u0c8e\u0c82\u0cac \u0cb9\u0cc6\u0cb8\u0cb0\u0cc1 \"\u0c9a\u0cbf\u0c82\u0ca4\u0cbf\u0cb8\u0cbf\u0ca6 \u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4\u0ca6 \u0cb6\u0cc1\u0cad\u0cbe\u0cb6\u0cc1\u0cad \u0cab\u0cb2\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca4\u0c95\u0ccd\u0cb7\u0ca3\u0cb5\u0cc7 \u0c92\u0ca6\u0c97\u0cbf\u0cb8\u0cc1\u0cb5 \u0c95\u0cb2\u0ccd\u0caa\u0cb5\u0cc3\u0c95\u0ccd\u0cb7-\u0cb8\u0cae\u0cbe\u0ca8\u0cb5\u0cbe\u0ca6 \u0cb0\u0ca4\u0ccd\u0ca8\" \u0c8e\u0c82\u0cac\u0cc1\u0ca6\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb8\u0cc2\u0c9a\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c97\u0ccd\u0cb0\u0c82\u0ca5\u0ca6 \u0caa\u0ccd\u0cb0\u0cbe\u0cb0\u0c82\u0cad\u0ca6\u0cb2\u0ccd\u0cb2\u0cc7 \u0cae\u0c82\u0c97\u0cb3\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c95\u0ccb\u0cb0\u0cbf\u0cb0\u0cc1\u0cb5\u0cc1\u0ca6\u0cb0\u0cbf\u0c82\u0ca6 \u0c87\u0ca6\u0cc1 \u0cae\u0cb9\u0ca4\u0ccd\u0cb5\u0ca6\u0ccd\u0ca6\u0cbe\u0c97\u0cbf\u0ca6\u0cc6.",1),A.aM("\u0928\u0928\u094d\u0926\u093e\u0926\u093f\u092c\u093e\u0923\u093e\u0938\u094d\u0924\u0925\u093e \u092d\u0926\u094d\u0930\u093e\u091c\u092f\u093e\u0930\u093f\u0915\u094d\u0924\u093e\u092a\u0942\u0930\u094d\u0923\u093e\u0903 \u0964\n\u092a\u094d\u0930\u0924\u093f\u092a\u0926\u093e\u0926\u094d\u092f\u093e\u0903 \u0938\u094d\u092e\u0943\u0924\u093e\u0903 \u092a\u0930\u094d\u092f\u093e\u092f\u0947\u0923 \u0938\u093f\u0924\u093e\u0938\u093f\u0924\u0947 \u092a\u0915\u094d\u0937\u0947 \u0965 \u0968 \u0965","mc_1_2","\u0cb6\u0cc1\u0c95\u0ccd\u0cb2 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c95\u0cc3\u0cb7\u0ccd\u0ca3 \u0caa\u0c95\u0ccd\u0cb7\u0c97\u0cb3\u0cc6\u0cb0\u0ca1\u0cb0\u0cb2\u0ccd\u0cb2\u0cc2 \u0caa\u0ccd\u0cb0\u0ca4\u0cbf\u0caa\u0ca6 (\u0caa\u0cbe\u0ca1\u0ccd\u0caf) \u0ca6\u0cbf\u0c82\u0ca6 \u0c86\u0cb0\u0c82\u0cad\u0c97\u0cca\u0c82\u0ca1\u0cc1 \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0c95\u0ccd\u0cb0\u0cae\u0cb5\u0cbe\u0c97\u0cbf \u0ca8\u0c82\u0ca6\u0cbe, \u0cad\u0ca6\u0ccd\u0cb0\u0cbe, \u0c9c\u0caf\u0cbe, \u0cb0\u0cbf\u0c95\u0ccd\u0ca4\u0cbe \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cbe \u0c8e\u0c82\u0ca6\u0cc1 \u0c90\u0ca6\u0cc1 \u0c97\u0cc1\u0c82\u0caa\u0cc1\u0c97\u0cb3\u0cbe\u0c97\u0cbf \u0cb5\u0cbf\u0cad\u0c9c\u0cbf\u0cb8\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6.","\u0ca8\u0c82\u0ca6\u0cbe\u0ca6\u0cbf\u0cac\u0cbe\u0ca3\u0cbe\u0cb8\u0ccd\u0ca4\u0ca5\u0cbe \u0cad\u0ca6\u0ccd\u0cb0\u0cbe\u0c9c\u0caf\u0cbe\u0cb0\u0cbf\u0c95\u0cbe\u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cbe\u0c83 \u0964\n\u0caa\u0ccd\u0cb0\u0ca4\u0cbf\u0caa\u0ca6\u0cbe\u0ca6\u0ccd\u0caf\u0cbe\u0c83 \u0cb8\u0ccd\u0cae\u0cc3\u0ca4\u0cbe\u0c83 \u0caa\u0cb0\u0ccd\u0caf\u0cbe\u0caf\u0cc7\u0ca3 \u0cb8\u0cbf\u0ca4\u0cbe\u0cb8\u0cbf\u0ca4\u0cc7 \u0caa\u0c95\u0ccd\u0cb7\u0cc7 \u0965 \u0ce8 \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0c97\u0ccd\u0cb0\u0cb9\u0c97\u0cb3 \u0cb8\u0c82\u0cac\u0c82\u0ca7): \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3 \u0c97\u0cc1\u0ca3 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0caa\u0ccd\u0cb0\u0cad\u0cbe\u0cb5\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca4\u0cbf\u0cb3\u0cbf\u0caf\u0cb2\u0cc1 \u0c90\u0ca6\u0cc1 \u0cb9\u0cc6\u0cb8\u0cb0\u0cc1\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0c87\u0ca1\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6. \u0ca8\u0c82\u0ca6\u0cbe (\u0cb6\u0cc1\u0c95\u0ccd\u0cb0\u0ca8 \u0c92\u0ca1\u0cc6\u0ca4\u0ca8), \u0cad\u0ca6\u0ccd\u0cb0\u0cbe (\u0cac\u0cc1\u0ca7\u0ca8 \u0c92\u0ca1\u0cc6\u0ca4\u0ca8), \u0c9c\u0caf\u0cbe (\u0cae\u0c82\u0c97\u0cb3\u0ca8 \u0c92\u0ca1\u0cc6\u0ca4\u0ca8), \u0cb0\u0cbf\u0c95\u0ccd\u0ca4\u0cbe (\u0cb6\u0ca8\u0cbf\u0caf \u0c92\u0ca1\u0cc6\u0ca4\u0ca8), \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cbe (\u0c9a\u0c82\u0ca6\u0ccd\u0cb0 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c97\u0cc1\u0cb0\u0cc1\u0cb5\u0cbf\u0ca8 \u0c92\u0ca1\u0cc6\u0ca4\u0ca8). \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c95\u0ccd\u0c95\u0cc6 \u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4 \u0ca8\u0ccb\u0ca1\u0cc1\u0cb5\u0cbe\u0c97 \u0ca4\u0cbf\u0ca5\u0cbf\u0caf \u0cb8\u0ccd\u0cb5\u0cad\u0cbe\u0cb5 (\u0c89\u0ca6\u0cbe: \u0c9c\u0caf\u0cbe-\u0c97\u0cc6\u0cb2\u0cc1\u0cb5\u0cc1 \u0ca4\u0cb0\u0cc1\u0cb5\u0c82\u0ca5\u0ca6\u0ccd\u0ca6\u0cc1) \u0cac\u0cb9\u0cb3 \u0cae\u0cc1\u0c96\u0ccd\u0caf. \u0c86\u0ca6\u0cb0\u0cc6 '\u0cb0\u0cbf\u0c95\u0ccd\u0ca4\u0cbe' \u0c8e\u0c82\u0ca6\u0cb0\u0cc6 \u0cac\u0cb0\u0cbf\u0ca6\u0cbe\u0ca6\u0ca6\u0ccd\u0ca6\u0cc1 (Empty), \u0cb0\u0cbf\u0c95\u0ccd\u0ca4\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0caf\u0cb2\u0ccd\u0cb2\u0cbf \u0cae\u0cbe\u0ca1\u0cbf\u0ca6 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cc1 \u0cb6\u0ca8\u0cbf\u0caf\u0c82\u0ca4\u0cc6 \u0ca8\u0cbf\u0ca7\u0cbe\u0ca8 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cac\u0cb0\u0cbf\u0ca6\u0cbe\u0c97\u0cc1\u0cb5\u0cc1\u0ca6\u0cb0\u0cbf\u0c82\u0ca6 \u0c86 \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb5\u0cb0\u0ccd\u0c9c\u0cbf\u0cb8\u0cac\u0cc7\u0c95\u0cc1.",2),A.aM("\u0928\u0928\u094d\u0926\u093e\u092f\u093e\u0902 \u0936\u0941\u0915\u094d\u0930\u0935\u093e\u0930\u0903 \u0938\u094d\u092f\u093e\u0924\u094d \u092d\u0926\u094d\u0930\u093e\u092f\u093e\u0902 \u092c\u0941\u0927\u0935\u093e\u0938\u0930\u0903 \u0964\n\u091c\u092f\u093e\u092f\u093e\u0902 \u0915\u0941\u091c\u0935\u093e\u0930\u0903 \u0938\u094d\u092f\u093e\u0924\u094d \u0930\u093f\u0915\u094d\u0924\u093e\u092f\u093e\u0902 \u0936\u0928\u093f\u0935\u093e\u0938\u0930\u0903 \u0965 \u0969 \u0965","mc_1_3","\u0ca8\u0c82\u0ca6\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0cb6\u0cc1\u0c95\u0ccd\u0cb0\u0cb5\u0cbe\u0cb0\u0cb5\u0cc2, \u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0cac\u0cc1\u0ca7\u0cb5\u0cbe\u0cb0\u0cb5\u0cc2, \u0c9c\u0caf\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0cae\u0c82\u0c97\u0cb3\u0cb5\u0cbe\u0cb0\u0cb5\u0cc2, \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb0\u0cbf\u0c95\u0ccd\u0ca4\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0cb6\u0ca8\u0cbf\u0cb5\u0cbe\u0cb0\u0cb5\u0cc2 \u0cac\u0c82\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 \u0cb5\u0cbf\u0cb6\u0cc7\u0cb7 \u0ca6\u0ccb\u0cb7\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c85\u0ca5\u0cb5\u0cbe \u0caf\u0ccb\u0c97\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c89\u0c82\u0c9f\u0cc1\u0cae\u0cbe\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.","\u0ca8\u0c82\u0ca6\u0cbe\u0caf\u0cbe\u0c82 \u0cb6\u0cc1\u0c95\u0ccd\u0cb0\u0cb5\u0cbe\u0cb0\u0c83 \u0cb8\u0ccd\u0caf\u0cbe\u0ca4\u0ccd \u0cad\u0ca6\u0ccd\u0cb0\u0cbe\u0caf\u0cbe\u0c82 \u0cac\u0cc1\u0ca7\u0cb5\u0cbe\u0cb8\u0cb0\u0c83 \u0964\n\u0c9c\u0caf\u0cbe\u0caf\u0cbe\u0c82 \u0c95\u0cc1\u0c9c\u0cb5\u0cbe\u0cb0\u0c83 \u0cb8\u0ccd\u0caf\u0cbe\u0ca4\u0ccd \u0cb0\u0cbf\u0c95\u0ccd\u0ca4\u0cbe\u0caf\u0cbe\u0c82 \u0cb6\u0ca8\u0cbf\u0cb5\u0cbe\u0cb8\u0cb0\u0c83 \u0965 \u0ce9 \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0c86\u0cb3\u0cb5\u0cbe\u0ca6 \u0caf\u0ccb\u0c97 \u0c97\u0ca3\u0cbf\u0ca4): \u0c87\u0ca6\u0cc1 \u0cae\u0c82\u0c97\u0cb3\u0c95\u0cb0 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c85\u0cae\u0c82\u0c97\u0cb3\u0c95\u0cb0 \u0caf\u0ccb\u0c97\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb2\u0cc6\u0c95\u0ccd\u0c95\u0cbe\u0c9a\u0cbe\u0cb0 \u0cae\u0cbe\u0ca1\u0cc1\u0cb5 \u0cb0\u0cb9\u0cb8\u0ccd\u0caf \u0cae\u0cc2\u0cb2\u0cb8\u0cc2\u0ca4\u0ccd\u0cb0. \u0caf\u0cbe\u0cb5 \u0c97\u0ccd\u0cb0\u0cb9\u0cb5\u0cc1 \u0caf\u0cbe\u0cb5 \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cc6 \u0c92\u0ca1\u0cc6\u0caf\u0ca8\u0ccb, \u0c86 \u0c97\u0ccd\u0cb0\u0cb9\u0ca6 \u0cb5\u0cbe\u0cb0\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0c85\u0ca6\u0cc7 \u0ca4\u0cbf\u0ca5\u0cbf \u0cac\u0c82\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0cb6\u0cbe\u0cb2\u0cbf '\u0cb8\u0cbf\u0ca6\u0ccd\u0ca7\u0cbf \u0caf\u0ccb\u0c97' \u0c85\u0ca5\u0cb5\u0cbe '\u0c85\u0cae\u0cc3\u0ca4 \u0caf\u0ccb\u0c97'\u0cb5\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c89\u0ca6\u0cbe\u0cb9\u0cb0\u0ca3\u0cc6\u0c97\u0cc6: \u0ca8\u0c82\u0ca6\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cc6 \u0c92\u0ca1\u0cc6\u0caf \u0cb6\u0cc1\u0c95\u0ccd\u0cb0, \u0c85\u0c82\u0ca6\u0cc1 \u0cb6\u0cc1\u0c95\u0ccd\u0cb0\u0cb5\u0cbe\u0cb0 \u0cac\u0c82\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 \u0cb8\u0cbf\u0ca6\u0ccd\u0ca7\u0cbf \u0caf\u0ccb\u0c97. \u0c86\u0ca6\u0cb0\u0cc6 \u0c87\u0ca6\u0cc7 \u0ca8\u0cbf\u0caf\u0cae\u0c95\u0ccd\u0c95\u0cc6 \u0cb5\u0cbf\u0cb0\u0cc1\u0ca6\u0ccd\u0ca7\u0cb5\u0cbe\u0c97\u0cbf \u0cac\u0cc7\u0cb0\u0cc6 \u0cb5\u0cbe\u0cb0-\u0ca4\u0cbf\u0ca5\u0cbf \u0cb8\u0cc7\u0cb0\u0cbf\u0ca6\u0cb0\u0cc6 \u0cae\u0cc3\u0ca4\u0ccd\u0caf\u0cc1 \u0caf\u0ccb\u0c97 \u0cac\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c87\u0ca6\u0cc1 \u0caa\u0ccd\u0cb0\u0c95\u0cc3\u0ca4\u0cbf\u0caf \u0c85\u0cb8\u0ccd\u0ca4\u0ccd\u0cb0\u0ca6\u0c82\u0ca4\u0cc6 \u0c95\u0cc6\u0cb2\u0cb8 \u0cae\u0cbe\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.",3),A.aM("\u092a\u0942\u0930\u094d\u0923\u093e\u092f\u093e\u0902 \u0917\u0941\u0930\u0941\u0935\u093e\u0930\u0903 \u0938\u094d\u092f\u093e\u0924\u094d \u0936\u094d\u0930\u0947\u0937\u094d\u0920\u0903 \u0938\u0930\u094d\u0935\u093e\u0930\u094d\u0925\u0938\u093e\u0927\u0915\u0903 \u0964\n\u090f\u0935\u0902 \u0935\u093e\u0930\u0924\u093f\u0925\u093f\u092f\u094b\u0917\u0947 \u0938\u093f\u0926\u094d\u0927\u093f\u092f\u094b\u0917\u0903 \u092a\u094d\u0930\u0915\u0940\u0930\u094d\u0924\u093f\u0924\u0903 \u0965 \u096a \u0965","mc_1_4",'\u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf (\u0ceb, \u0ce7\u0ce6, \u0ce7\u0ceb) \u0c97\u0cc1\u0cb0\u0cc1\u0cb5\u0cbe\u0cb0 \u0cac\u0c82\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0cb6\u0ccd\u0cb0\u0cc7\u0cb7\u0ccd\u0ca0\u0cb5\u0cbe\u0ca6\u0ca6\u0ccd\u0ca6\u0cc1 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c8e\u0cb2\u0ccd\u0cb2 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb8\u0cbe\u0ca7\u0cbf\u0cb8\u0cbf\u0c95\u0cca\u0ca1\u0cc1\u0cb5\u0c82\u0ca4\u0cb9\u0ca6\u0ccd\u0ca6\u0cbe\u0c97\u0cbf\u0ca6\u0cc6. \u0c88 \u0cb0\u0cc0\u0ca4\u0cbf\u0caf\u0cbe\u0c97\u0cbf \u0cb5\u0cbe\u0cb0 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3 \u0caf\u0ccb\u0c97\u0ca6\u0cbf\u0c82\u0ca6 "\u0cb8\u0cbf\u0ca6\u0ccd\u0ca7\u0cbf \u0caf\u0ccb\u0c97" \u0c89\u0c82\u0c9f\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6 \u0c8e\u0c82\u0ca6\u0cc1 \u0cb9\u0cc7\u0cb3\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6.',"\u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cbe\u0caf\u0cbe\u0c82 \u0c97\u0cc1\u0cb0\u0cc1\u0cb5\u0cbe\u0cb0\u0c83 \u0cb8\u0ccd\u0caf\u0cbe\u0ca4\u0ccd \u0cb6\u0ccd\u0cb0\u0cc7\u0cb7\u0ccd\u0ca0\u0c83 \u0cb8\u0cb0\u0ccd\u0cb5\u0cbe\u0cb0\u0ccd\u0ca5\u0cb8\u0cbe\u0ca7\u0c95\u0c83 \u0964\n\u0c8f\u0cb5\u0c82 \u0cb5\u0cbe\u0cb0\u0ca4\u0cbf\u0ca5\u0cbf\u0cb0\u0ccd\u0caf\u0ccb\u0c97\u0cc7 \u0cb8\u0cbf\u0ca6\u0ccd\u0ca7\u0cbf\u0caf\u0ccb\u0c97\u0c83 \u0caa\u0ccd\u0cb0\u0c95\u0cc0\u0cb0\u0ccd\u0ca4\u0cbf\u0ca4\u0c83 \u0965 \u0cea \u0965",'\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0cae\u0cb9\u0cbe\u0cb8\u0cbf\u0ca6\u0ccd\u0ca7\u0cbf \u0caf\u0ccb\u0c97): \u0c9c\u0ccd\u0caf\u0ccb\u0ca4\u0cbf\u0cb7\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cac\u0cc3\u0cb9\u0cb8\u0ccd\u0caa\u0ca4\u0cbf (\u0c97\u0cc1\u0cb0\u0cc1) \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0cb6\u0ccd\u0cb0\u0cc7\u0cb7\u0ccd\u0ca0 \u0cb6\u0cc1\u0cad\u0c97\u0ccd\u0cb0\u0cb9, \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cc1 (\u0ceb,\u0ce7\u0ce6,\u0ce7\u0ceb) \u0cb8\u0c82\u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0ca4\u0cc6\u0caf\u0ca8\u0ccd\u0ca8\u0cc1 (\u0ce7\u0ce6\u0ce6% \u0cac\u0cb2) \u0caa\u0ccd\u0cb0\u0ca4\u0cbf\u0ca8\u0cbf\u0ca7\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6. \u0c87\u0cb5\u0cc6\u0cb0\u0ca1\u0cb0 \u0cb8\u0c82\u0c97\u0cae\u0cb5\u0cc1 "\u0cae\u0cb9\u0cbe\u0cb8\u0cbf\u0ca6\u0ccd\u0ca7\u0cbf \u0caf\u0ccb\u0c97"\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb8\u0cc3\u0cb7\u0ccd\u0c9f\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c88 \u0cb8\u0c82\u0caf\u0ccb\u0c9c\u0ca8\u0cc6\u0caf\u0cc1 \u0c8e\u0cb7\u0ccd\u0c9f\u0cca\u0c82\u0ca6\u0cc1 \u0caa\u0ccd\u0cb0\u0cac\u0cb2\u0cb5\u0cc6\u0c82\u0ca6\u0cb0\u0cc6, \u0c9c\u0cbe\u0ca4\u0c95\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf\u0cb0\u0cc1\u0cb5 \u0c87\u0ca4\u0cb0 \u0cb8\u0ca3\u0ccd\u0ca3-\u0caa\u0cc1\u0c9f\u0ccd\u0c9f \u0ca8\u0cc2\u0cb0\u0cc1 \u0ca6\u0ccb\u0cb7\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 (\u0ca6\u0ccb\u0cb7-\u0cb9\u0cb0) \u0ca8\u0cbe\u0cb6\u0cae\u0cbe\u0ca1\u0cc1\u0cb5 \u0cb6\u0c95\u0ccd\u0ca4\u0cbf \u0c87\u0ca6\u0c95\u0ccd\u0c95\u0cbf\u0ca6\u0cc6. \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0ca6\u0cca\u0ca1\u0ccd\u0ca1 \u0cb5\u0ccd\u0caf\u0cb5\u0cb9\u0cbe\u0cb0, \u0cb5\u0cbf\u0ca6\u0ccd\u0caf\u0cbe\u0cb0\u0c82\u0cad \u0cae\u0cc1\u0c82\u0ca4\u0cbe\u0ca6 \u0ca6\u0ccb\u0cb7\u0cb0\u0cb9\u0cbf\u0ca4 \u0c86\u0cb0\u0c82\u0cad\u0c95\u0ccd\u0c95\u0cc6 \u0c87\u0ca6\u0cc1 \u0c85\u0ca4\u0ccd\u0ca4\u0ccd\u0caf\u0cc1\u0ca4\u0ccd\u0ca4\u0cae \u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4.',4),A.aM("\u0906\u0926\u093f\u0924\u094d\u092f\u0947 \u091a\u0928\u094d\u0926\u094d\u0930\u0935\u093e\u0930\u0947 \u091a \u0928\u0928\u094d\u0926\u093e\u0924\u093f\u0925\u093f\u0935\u093f\u0935\u0930\u094d\u091c\u0928\u092e\u094d \u0964\n\u0915\u0930\u094d\u0924\u0935\u094d\u092f\u0902 \u0938\u0930\u094d\u0935\u0915\u093e\u0930\u094d\u092f\u0947\u0937\u0941 \u0935\u093f\u092a\u0924\u094d\u0924\u094d\u092f\u092d\u093e\u0935\u092e\u093f\u091a\u094d\u091b\u0924\u093e \u0965 \u096b \u0965","mc_1_5","\u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb8\u0ccb\u0cae\u0cb5\u0cbe\u0cb0\u0c97\u0cb3\u0c82\u0ca6\u0cc1 \u0ca8\u0c82\u0ca6\u0cbe (\u0ce7, \u0cec, \u0ce7\u0ce7) \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cc1 \u0c92\u0c82\u0ca6\u0cc7 \u0ca6\u0cbf\u0ca8 \u0cac\u0c82\u0ca6\u0cb0\u0cc6, \u0ca4\u0ca8\u0c97\u0cc6 \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0cb5\u0cbf\u0caa\u0ca4\u0ccd\u0ca4\u0cc1 (\u0cb8\u0c82\u0c95\u0c9f) \u0cac\u0cbe\u0cb0\u0ca6\u0cbf\u0cb0\u0cb2\u0cbf \u0c8e\u0c82\u0ca6\u0cc1 \u0cac\u0caf\u0cb8\u0cc1\u0cb5\u0cb5\u0ca8\u0cc1 \u0c8e\u0cb2\u0ccd\u0cb2\u0cbe \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0c86 \u0ca6\u0cbf\u0ca8\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb5\u0cb0\u0ccd\u0c9c\u0cbf\u0cb8\u0cac\u0cc7\u0c95\u0cc1 (\u0cac\u0cbf\u0ca1\u0cac\u0cc7\u0c95\u0cc1).","\u0c86\u0ca6\u0cbf\u0ca4\u0ccd\u0caf\u0cc7 \u0c9a\u0c82\u0ca6\u0ccd\u0cb0\u0cb5\u0cbe\u0cb0\u0cc7 \u0c9a \u0ca8\u0c82\u0ca6\u0cbe\u0ca4\u0cbf\u0ca5\u0cbf\u0cb5\u0cbf\u0cb5\u0cb0\u0ccd\u0c9c\u0ca8\u0cae\u0ccd \u0964\n\u0c95\u0cb0\u0ccd\u0ca4\u0cb5\u0ccd\u0caf\u0c82 \u0cb8\u0cb0\u0ccd\u0cb5\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0cc7\u0cb7\u0cc1 \u0cb5\u0cbf\u0caa\u0ca4\u0ccd\u0ca4\u0ccd\u0caf\u0cad\u0cbe\u0cb5\u0cae\u0cbf\u0c9a\u0ccd\u0c9b\u0ca4\u0cbe \u0965 \u0ceb \u0965",'\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0ca6\u0c97\u0ccd\u0ca7 \u0caf\u0ccb\u0c97\u0ca6 \u0c92\u0cb3\u0ca8\u0ccb\u0c9f): \u0cb8\u0cc2\u0cb0\u0ccd\u0caf (\u0c85\u0c97\u0ccd\u0ca8\u0cbf) \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c9a\u0c82\u0ca6\u0ccd\u0cb0 (\u0c9c\u0cb2) \u0cb0\u0cbe\u0c9c\u0c97\u0ccd\u0cb0\u0cb9\u0c97\u0cb3\u0cc1. \u0ca8\u0c82\u0ca6\u0cbe \u0ca4\u0cbf\u0ca5\u0cbf\u0caf\u0ca8\u0ccd\u0ca8\u0cc1 (\u0c86\u0ca8\u0c82\u0ca6/\u0cb6\u0cc1\u0c95\u0ccd\u0cb0) \u0cb8\u0cc2\u0cb0\u0ccd\u0caf-\u0c9a\u0c82\u0ca6\u0ccd\u0cb0\u0cb0 \u0cb5\u0cbe\u0cb0\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0c86\u0cb0\u0c82\u0cad\u0cbf\u0cb8\u0cc1\u0cb5\u0cbe\u0c97 \u0c98\u0cb0\u0ccd\u0cb7\u0ca3\u0cc6 \u0c89\u0c82\u0c9f\u0cbe\u0c97\u0cbf "\u0ca6\u0c97\u0ccd\u0ca7" (\u0cb8\u0cc1\u0c9f\u0ccd\u0c9f\u0cc1\u0cb9\u0ccb\u0c97\u0cc1\u0cb5) \u0caf\u0ccb\u0c97 \u0cb8\u0cc3\u0cb7\u0ccd\u0c9f\u0cbf\u0caf\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c8e\u0cb7\u0ccd\u0c9f\u0cc7 \u0c92\u0cb3\u0ccd\u0cb3\u0cc6\u0caf \u0c9c\u0cbe\u0ca4\u0c95\u0cb5\u0cbf\u0ca6\u0ccd\u0ca6\u0cb0\u0cc2, \u0c88 \u0ca6\u0c97\u0ccd\u0ca7 \u0caf\u0ccb\u0c97\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf \u0c86\u0cb0\u0c82\u0cad\u0cbf\u0cb8\u0cbf\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 \u0c85\u0c95\u0ccd\u0cb7\u0cb0\u0cb6\u0c83 \u0cac\u0cc2\u0ca6\u0cbf\u0caf\u0c82\u0ca4\u0cc6 \u0ca8\u0cbf\u0cb0\u0cc0\u0c95\u0ccd\u0cb7\u0cbf\u0ca4 \u0cab\u0cb2 \u0c95\u0cca\u0ca1\u0cc1\u0cb5\u0cc1\u0ca6\u0cbf\u0cb2\u0ccd\u0cb2. \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0c87\u0ca6\u0ca8\u0ccd\u0ca8\u0cc1 \u0c95\u0c9f\u0ccd\u0c9f\u0cc1\u0ca8\u0cbf\u0c9f\u0ccd\u0c9f\u0cbe\u0c97\u0cbf \u0ca4\u0ccd\u0caf\u0c9c\u0cbf\u0cb8\u0cb2\u0cc7\u0cac\u0cc7\u0c95\u0cc1.',5),A.aM("\u0926\u094d\u0935\u093e\u0926\u0936\u094d\u092f\u0947\u0915\u093e\u0926\u0936\u0940 \u0937\u0937\u094d\u0920\u0940 \u0924\u0943\u0924\u0940\u092f\u093e \u0928\u0935\u092e\u0940 \u0924\u0925\u093e \u0964\n\u0905\u0937\u094d\u091f\u092e\u0940 \u092a\u091e\u094d\u091a\u092e\u0940 \u091a\u0948\u0935 \u0938\u0942\u0930\u094d\u092f\u093e\u0926\u093f\u0926\u093f\u0935\u0938\u0947\u0937\u094d\u0935\u093f\u0939 \u0965 \u096c \u0965","mc_1_6","\u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0\u0ca6\u0cbf\u0c82\u0ca6 \u0cb6\u0ca8\u0cbf\u0cb5\u0cbe\u0cb0\u0ca6\u0cb5\u0cb0\u0cc6\u0c97\u0cc6 \u0c95\u0ccd\u0cb0\u0cae\u0cb5\u0cbe\u0c97\u0cbf \u0ce7\u0ce8, \u0ce7\u0ce7, \u0cec, \u0ce9, \u0cef, \u0cee \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0ceb \u0ca8\u0cc7 \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cc1 \u0ca6\u0c97\u0ccd\u0ca7 \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cc6\u0ca8\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6. \u0c87\u0cb5\u0cc1 \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0cb5\u0cb0\u0ccd\u0c9c\u0ccd\u0caf.","\u0ca6\u0ccd\u0cb5\u0cbe\u0ca6\u0cb6\u0ccd\u0caf\u0cc7\u0c95\u0cbe\u0ca6\u0cb6\u0cc0 \u0cb7\u0cb7\u0ccd\u0ca0\u0cc0 \u0ca4\u0cc3\u0ca4\u0cc0\u0caf\u0cbe \u0ca8\u0cb5\u0cae\u0cc0 \u0ca4\u0ca5\u0cbe \u0964\n\u0c85\u0cb7\u0ccd\u0c9f\u0cae\u0cc0 \u0caa\u0c82\u0c9a\u0cae\u0cc0 \u0c9a\u0cc8\u0cb5 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0cbe\u0ca6\u0cbf\u0ca6\u0cbf\u0cb5\u0cb8\u0cc7\u0cb7\u0ccd\u0cb5\u0cbf\u0cb9 \u0965 \u0cec \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0ca4\u0cbf\u0ca5\u0cbf-\u0cb5\u0cbf\u0cb7 \u0ca6\u0ccb\u0cb7): \u0ce7\u0ce8\u0ca8\u0cc7 \u0ca4\u0cbf\u0ca5\u0cbf\u0caf \u0ca6\u0cbf\u0ca8 \u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0 \u0cac\u0c82\u0ca6\u0cb0\u0cc6 \u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0c97\u0cb3 \u0c98\u0cb0\u0ccd\u0cb7\u0ca3\u0cc6\u0caf\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6, \u0c87\u0ca6\u0cc1 \u0ca8\u0cbf\u0cb0\u0ccd\u0ca6\u0cbf\u0cb7\u0ccd\u0c9f \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0cc1 \u0ca8\u0cbf\u0cb0\u0ccd\u0ca6\u0cbf\u0cb7\u0ccd\u0c9f \u0cb5\u0cbe\u0cb0\u0ca6 \u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0caf\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb5\u0cbf\u0cb0\u0ccb\u0ca7\u0cbf\u0cb8\u0cc1\u0cb5 \u0caa\u0ccd\u0cb0\u0c95\u0ccd\u0cb0\u0cbf\u0caf\u0cc6. \u0c87\u0cb5\u0cc1\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 '\u0ca6\u0c97\u0ccd\u0ca7 \u0ca4\u0cbf\u0ca5\u0cbf' \u0c85\u0ca5\u0cb5\u0cbe '\u0ca4\u0cbf\u0ca5\u0cbf-\u0cb5\u0cbf\u0cb7' \u0c8e\u0c82\u0ca6\u0cc1 \u0c95\u0cb0\u0cc6\u0caf\u0cb2\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0-\u0ca6\u0ccd\u0cb5\u0cbe\u0ca6\u0cb6\u0cbf(\u0ce7\u0ce8), \u0cb8\u0ccb\u0cae-\u0c8f\u0c95\u0cbe\u0ca6\u0cb6\u0cbf(\u0ce7\u0ce7), \u0cae\u0c82\u0c97\u0cb3-\u0cb7\u0cb7\u0ccd\u0ca0\u0cbf(\u0cec), \u0cac\u0cc1\u0ca7-\u0ca4\u0cc3\u0ca4\u0cc0\u0caf\u0cbe(\u0ce9), \u0c97\u0cc1\u0cb0\u0cc1-\u0ca8\u0cb5\u0cae\u0cbf(\u0cef), \u0cb6\u0cc1\u0c95\u0ccd\u0cb0-\u0c85\u0cb7\u0ccd\u0c9f\u0cae\u0cbf(\u0cee) \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb6\u0ca8\u0cbf-\u0caa\u0c82\u0c9a\u0cae\u0cbf(\u0ceb). \u0c88 \u0ca6\u0ccb\u0cb7\u0ca6 \u0cb8\u0cae\u0caf\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0c97\u0cc3\u0cb9\u0caa\u0ccd\u0cb0\u0cb5\u0cc7\u0cb6, \u0cb5\u0ccd\u0caf\u0cbe\u0caa\u0cbe\u0cb0 \u0c86\u0cb0\u0c82\u0cad \u0cae\u0cbe\u0ca1\u0cbf\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cb0 \u0c86\u0caf\u0cc1\u0cb7\u0ccd\u0caf \u0ca8\u0cbe\u0cb6\u0cb5\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.",6),A.aM("\u091a\u0924\u0941\u0930\u094d\u0925\u0940 \u0937\u0937\u094d\u0920\u092f\u0937\u094d\u091f\u092e\u0940 \u091a \u0928\u0935\u092e\u0940 \u0926\u094d\u0935\u093e\u0926\u0936\u0940 \u0924\u0925\u093e \u0964\n\u0924\u094d\u0930\u092f\u094b\u0926\u0936\u0940 \u091a \u092a\u094d\u0930\u0924\u093f\u092a\u0926\u094d \u0915\u094d\u0930\u092e\u0947\u0923 \u0935\u093f\u0937\u0938\u0902\u091c\u094d\u091e\u093f\u0915\u093e\u0903 \u0965 \u096d \u0965","mc_1_7",'\u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0\u0ca6\u0cbf\u0c82\u0ca6 \u0cb6\u0ca8\u0cbf\u0cb5\u0cbe\u0cb0\u0ca6\u0cb5\u0cb0\u0cc6\u0c97\u0cc6 \u0cb8\u0c82\u0cad\u0cb5\u0cbf\u0cb8\u0cc1\u0cb5 \u0cea, \u0cec, \u0cee, \u0cef, \u0ce7\u0ce8, \u0ce7\u0ce9 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0ce7 \u0ca8\u0cc7 \u0ca4\u0cbf\u0ca5\u0cbf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 "\u0cb5\u0cbf\u0cb7 \u0caf\u0ccb\u0c97" \u0c85\u0ca5\u0cb5\u0cbe "\u0cb5\u0cbf\u0cb7 \u0ca4\u0cbf\u0ca5\u0cbf" \u0c8e\u0c82\u0ca6\u0cc1 \u0c95\u0cb0\u0cc6\u0caf\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6.',"\u0c9a\u0ca4\u0cc1\u0cb0\u0ccd\u0ca5\u0cc0 \u0cb7\u0cb7\u0ccd\u0ca0\u0ccd\u0caf\u0cb7\u0ccd\u0c9f\u0cae\u0cc0 \u0c9a \u0ca8\u0cb5\u0cae\u0cc0 \u0ca6\u0ccd\u0cb5\u0cbe\u0ca6\u0cb6\u0cc0 \u0ca4\u0ca5\u0cbe \u0964\n\u0ca4\u0ccd\u0cb0\u0caf\u0ccb\u0ca6\u0cb6\u0cc0 \u0c9a \u0caa\u0ccd\u0cb0\u0ca4\u0cbf\u0caa\u0ca6\u0ccd \u0c95\u0ccd\u0cb0\u0cae\u0cc7\u0ca3 \u0cb5\u0cbf\u0cb7\u0cb8\u0c82\u0c9c\u0ccd\u0c9e\u0cbf\u0c95\u0cbe\u0c83 \u0965 \u0ced \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0cb5\u0cbf\u0cb7 \u0caf\u0ccb\u0c97\u0ca6 \u0caa\u0ccd\u0cb0\u0cad\u0cbe\u0cb5): \u0cb9\u0cbe\u0cb2\u0cbf\u0ca8 \u0cae\u0ca1\u0c95\u0cc6\u0c97\u0cc6 \u0c92\u0c82\u0ca6\u0cc1 \u0ca4\u0cca\u0c9f\u0ccd\u0c9f\u0cc1 \u0cb5\u0cbf\u0cb7 \u0cac\u0cbf\u0ca6\u0ccd\u0ca6\u0cb0\u0cc2 \u0cb9\u0cc7\u0c97\u0cc6 \u0c87\u0ca1\u0cc0 \u0cb9\u0cbe\u0cb2\u0cc1 \u0cb5\u0cbf\u0cb7\u0cb5\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6\u0caf\u0ccb, \u0cb9\u0cbe\u0c97\u0cc6\u0caf\u0cc7 \u0c88 \u0cb5\u0cbe\u0cb0-\u0ca4\u0cbf\u0ca5\u0cbf\u0caf \u0cb8\u0c82\u0caf\u0ccb\u0c9c\u0ca8\u0cc6\u0caf\u0cc1 \u0c86\u0cb0\u0c82\u0cad\u0cbf\u0cb8\u0cc1\u0cb5 \u0c95\u0cc6\u0cb2\u0cb8\u0c95\u0ccd\u0c95\u0cc6 \u0cb5\u0cbf\u0cb7\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 (Toxicity) \u0cb8\u0cc7\u0cb0\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0 \u0ca6\u0cbf\u0cb5\u0cb8 \u0c9a\u0ca4\u0cc1\u0cb0\u0ccd\u0ca5\u0cbf (\u0c97\u0ca3\u0caa\u0ca4\u0cbf/\u0caf\u0cae\u0ca8 \u0c92\u0ca1\u0cc6\u0ca4\u0ca8) \u0cac\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8 \u0c89\u0c97\u0ccd\u0cb0\u0ca4\u0cc6 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c9a\u0ca4\u0cc1\u0cb0\u0ccd\u0ca5\u0cbf\u0caf \u0c95\u0ca0\u0ccb\u0cb0\u0ca4\u0cc6 \u0cb8\u0cc7\u0cb0\u0cbf \u0cb5\u0cbf\u0cb7\u0cae \u0cb5\u0cbe\u0ca4\u0cbe\u0cb5\u0cb0\u0ca3 \u0cb8\u0cc3\u0cb7\u0ccd\u0c9f\u0cbf\u0caf\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c86\u0ca6\u0ccd\u0ca6\u0cb0\u0cbf\u0c82\u0ca6 \u0caa\u0ccd\u0cb0\u0cae\u0cc1\u0c96 \u0c92\u0caa\u0ccd\u0caa\u0c82\u0ca6\u0c97\u0cb3\u0cc1, \u0cb9\u0cca\u0cb8 \u0c95\u0cc6\u0cb2\u0cb8\u0ca6 \u0c86\u0cb0\u0c82\u0cad\u0c95\u0ccd\u0c95\u0cc6 \u0c88 \u0ca6\u0cbf\u0ca8\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca4\u0ccd\u0caf\u0c9c\u0cbf\u0cb8\u0cac\u0cc7\u0c95\u0cc1.",7),A.aM("\u092e\u0918\u093e \u0935\u093f\u0936\u093e\u0916\u093e \u0915\u0943\u0924\u094d\u0924\u093f\u0915\u093e \u092e\u0942\u0932\u0902 \u092a\u0942\u0930\u094d\u0935\u093e \u091a \u0930\u094b\u0939\u093f\u0923\u0940 \u0964\n\u0939\u0938\u094d\u0924\u0936\u094d\u091a\u093e\u092a\u093f \u0924\u0924\u094b \u0927\u093f\u0937\u094d\u0923\u094d\u092f\u0902 \u0938\u0942\u0930\u094d\u092f\u093e\u0926\u094c \u092f\u092e\u0918\u0923\u094d\u091f\u0915\u0903 \u0965 \u096e \u0965","mc_1_8",'\u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0\u0ca6\u0cbf\u0c82\u0ca6 \u0cb6\u0ca8\u0cbf\u0cb5\u0cbe\u0cb0\u0ca6\u0cb5\u0cb0\u0cc6\u0c97\u0cc6 \u0c95\u0ccd\u0cb0\u0cae\u0cb5\u0cbe\u0c97\u0cbf \u0cae\u0c98\u0cbe, \u0cb5\u0cbf\u0cb6\u0cbe\u0c96\u0cbe, \u0c95\u0cc3\u0ca4\u0ccd\u0ca4\u0cbf\u0c95\u0cbe, \u0cae\u0cc2\u0cb2\u0cbe, \u0caa\u0cc2\u0cb0\u0ccd\u0cb5\u0cbe, \u0cb0\u0ccb\u0cb9\u0cbf\u0ca3\u0cbf \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb9\u0cb8\u0ccd\u0ca4 \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0c97\u0cb3\u0cc1 \u0cac\u0c82\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 "\u0caf\u0cae\u0c98\u0c82\u0c9f \u0caf\u0ccb\u0c97" \u0c8e\u0ca8\u0cbf\u0cb8\u0cbf\u0c95\u0cca\u0cb3\u0ccd\u0cb3\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.',"\u0cae\u0c98\u0cbe \u0cb5\u0cbf\u0cb6\u0cbe\u0c96\u0cbe \u0c95\u0cc3\u0ca4\u0ccd\u0ca4\u0cbf\u0c95\u0cbe \u0cae\u0cc2\u0cb2\u0c82 \u0caa\u0cc2\u0cb0\u0ccd\u0cb5\u0cbe \u0c9a \u0cb0\u0ccb\u0cb9\u0cbf\u0ca3\u0cc0 \u0964\n\u0cb9\u0cb8\u0ccd\u0ca4\u0cb6\u0ccd\u0c9a\u0cbe\u0caa\u0cbf \u0ca4\u0ca4\u0ccb \u0ca7\u0cbf\u0cb7\u0ccd\u0ca3\u0ccd\u0caf\u0c82 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0cbe\u0ca6\u0ccc \u0caf\u0cae\u0c98\u0c82\u0c9f\u0c95\u0c83 \u0965 \u0cee \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0cae\u0cc3\u0ca4\u0ccd\u0caf\u0cc1 \u0c98\u0c82\u0c9f\u0cc6): '\u0caf\u0cae' \u0c8e\u0c82\u0ca6\u0cb0\u0cc6 \u0cb8\u0cbe\u0cb5\u0cc1, '\u0c98\u0c82\u0c9f\u0cc6' (\u0c98\u0c82\u0c9f\u0c95) \u0c8e\u0c82\u0ca6\u0cb0\u0cc6 \u0cb8\u0cbe\u0cb5\u0cbf\u0ca8 \u0cae\u0cc1\u0ca8\u0ccd\u0cb8\u0cc2\u0c9a\u0ca8\u0cc6. \u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0-\u0cae\u0c98\u0cbe, \u0cb8\u0ccb\u0cae\u0cb5\u0cbe\u0cb0-\u0cb5\u0cbf\u0cb6\u0cbe\u0c96\u0cbe \u0c87\u0ca4\u0ccd\u0caf\u0cbe\u0ca6\u0cbf \u0cb8\u0c82\u0caf\u0ccb\u0c9c\u0ca8\u0cc6\u0c97\u0cb3\u0cc1 \u0caf\u0cae\u0c98\u0c82\u0c9f \u0caf\u0ccb\u0c97 \u0cb8\u0cc3\u0cb7\u0ccd\u0c9f\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6. \u0c88 \u0cb8\u0cae\u0caf\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0cb9\u0cca\u0cb8 \u0cb0\u0ccb\u0c97\u0c95\u0ccd\u0c95\u0cc6 \u0c9a\u0cbf\u0c95\u0cbf\u0ca4\u0ccd\u0cb8\u0cc6, \u0cae\u0cbe\u0ca4\u0ccd\u0cb0\u0cc6 \u0c86\u0cb0\u0c82\u0cad, \u0cb6\u0cb8\u0ccd\u0ca4\u0ccd\u0cb0\u0c9a\u0cbf\u0c95\u0cbf\u0ca4\u0ccd\u0cb8\u0cc6, \u0caa\u0ccd\u0cb0\u0caf\u0cbe\u0ca3, \u0c85\u0ca5\u0cb5\u0cbe \u0cb6\u0cc1\u0cad \u0cb8\u0cae\u0cbe\u0cb0\u0c82\u0cad\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cbf\u0ca6\u0cb0\u0cc6 \u0caa\u0ccd\u0cb0\u0cbe\u0ca3\u0cbe\u0caa\u0cbe\u0caf \u0c85\u0ca5\u0cb5\u0cbe \u0ca8\u0cb7\u0ccd\u0c9f \u0c95\u0c9f\u0ccd\u0c9f\u0cbf\u0c9f\u0ccd\u0c9f \u0cac\u0cc1\u0ca4\u0ccd\u0ca4\u0cbf. \u0c86\u0ca6\u0cb0\u0cc6 \u0c85\u0c9a\u0ccd\u0c9a\u0cb0\u0cbf\u0caf \u0cb5\u0cbf\u0c9a\u0cbe\u0cb0\u0cb5\u0cc6\u0c82\u0ca6\u0cb0\u0cc6: \u0cb6\u0ca4\u0ccd\u0cb0\u0cc1\u0ca8\u0cbe\u0cb6, \u0cae\u0cbe\u0c9f-\u0cae\u0c82\u0ca4\u0ccd\u0cb0, \u0c89\u0c9a\u0ccd\u0c9a\u0cbe\u0c9f\u0ca8\u0cc6\u0caf\u0c82\u0ca4\u0cb9 \u0c95\u0ccd\u0cb0\u0cc2\u0cb0 \u0c95\u0cc6\u0cb2\u0cb8\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0c88 \u0caf\u0ccb\u0c97 \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0caa\u0ccd\u0cb0\u0cad\u0cbe\u0cb5\u0cb6\u0cbe\u0cb2\u0cbf.",8),A.aM("\u092e\u0942\u0932\u0902 \u0936\u094d\u0930\u0935\u0923\u092e\u092d\u093f\u091c\u093f\u0924\u094d \u0915\u0943\u0924\u094d\u0924\u093f\u0915\u093e \u0930\u0947\u0935\u0924\u0940 \u0924\u0925\u093e \u0964\n\u0930\u094b\u0939\u093f\u0923\u0940 \u0938\u094d\u0935\u093e\u0924\u093f \u0928\u0915\u094d\u0937\u0924\u094d\u0930\u0902 \u0938\u0942\u0930\u094d\u092f\u093e\u0926\u094c \u0915\u093e\u0915\u092f\u094b\u0917\u0915\u0903 \u0965 \u096f \u0965","mc_1_9",'\u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0\u0ca6\u0cbf\u0c82\u0ca6 \u0cb6\u0ca8\u0cbf\u0cb5\u0cbe\u0cb0\u0ca6\u0cb5\u0cb0\u0cc6\u0c97\u0cc6 \u0cae\u0cc2\u0cb2\u0cbe, \u0cb6\u0ccd\u0cb0\u0cb5\u0ca3, \u0c85\u0cad\u0cbf\u0c9c\u0cbf\u0ca4\u0ccd, \u0c95\u0cc3\u0ca4\u0ccd\u0ca4\u0cbf\u0c95\u0cbe, \u0cb0\u0cc7\u0cb5\u0ca4\u0cc0, \u0cb0\u0ccb\u0cb9\u0cbf\u0ca3\u0cc0 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb8\u0ccd\u0cb5\u0cbe\u0ca4\u0cbf \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0c97\u0cb3\u0cc1 \u0cac\u0c82\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 "\u0c95\u0cbe\u0c95 \u0caf\u0ccb\u0c97" (\u0c85\u0ca5\u0cb5\u0cbe \u0ca7\u0ccd\u0cb5\u0cbe\u0c82\u0c95\u0ccd\u0cb7 \u0caf\u0ccb\u0c97) \u0c86\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.',"\u0cae\u0cc2\u0cb2\u0c82 \u0cb6\u0ccd\u0cb0\u0cb5\u0ca3\u0cae\u0cad\u0cbf\u0c9c\u0cbf\u0ca4\u0ccd \u0c95\u0cc3\u0ca4\u0ccd\u0ca4\u0cbf\u0c95\u0cbe \u0cb0\u0cc7\u0cb5\u0ca4\u0cc0 \u0ca4\u0ca5\u0cbe \u0964\n\u0cb0\u0ccb\u0cb9\u0cbf\u0ca3\u0cc0 \u0cb8\u0ccd\u0cb5\u0cbe\u0ca4\u0cbf \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0c82 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0cbe\u0ca6\u0ccc \u0c95\u0cbe\u0c95\u0caf\u0ccb\u0c97\u0c95\u0c83 \u0965 \u0cef \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0c95\u0cbe\u0c95 \u0caf\u0ccb\u0c97 / \u0c85\u0cb8\u0ccd\u0ca5\u0cbf\u0cb0\u0ca4\u0cc6): '\u0c95\u0cbe\u0c95' \u0c8e\u0c82\u0ca6\u0cb0\u0cc6 \u0c95\u0cbe\u0c97\u0cc6. \u0c95\u0cbe\u0c97\u0cc6\u0caf\u0cc1 \u0cb9\u0cc7\u0c97\u0cc6 \u0c92\u0c82\u0ca6\u0cc7 \u0c95\u0cca\u0c82\u0cac\u0cc6\u0caf\u0cb2\u0ccd\u0cb2\u0cbf \u0cb9\u0cc6\u0c9a\u0ccd\u0c9a\u0cc1 \u0cb9\u0cca\u0ca4\u0ccd\u0ca4\u0cc1 \u0c95\u0cc2\u0cb0\u0ca6\u0cc6 \u0c9a\u0ca1\u0caa\u0ca1\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0cbe \u0cb9\u0cbe\u0cb0\u0cbe\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6\u0caf\u0ccb, \u0cb9\u0cbe\u0c97\u0cc6\u0caf\u0cc7 \u0c88 \u0c95\u0cbe\u0c95 (\u0ca7\u0ccd\u0cb5\u0cbe\u0c82\u0c95\u0ccd\u0cb7) \u0caf\u0ccb\u0c97\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cae\u0cbe\u0ca1\u0cbf\u0ca6 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0ca8\u0cc6\u0cb2\u0cc6 \u0c87\u0cb0\u0cc1\u0cb5\u0cc1\u0ca6\u0cbf\u0cb2\u0ccd\u0cb2. \u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0 \u0cae\u0cc2\u0cb2\u0cbe \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0, \u0cb8\u0ccb\u0cae\u0cb5\u0cbe\u0cb0 \u0cb6\u0ccd\u0cb0\u0cb5\u0ca3 \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0 \u0c87\u0ca4\u0ccd\u0caf\u0cbe\u0ca6\u0cbf. \u0c88 \u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cb5\u0ccd\u0caf\u0cbe\u0caa\u0cbe\u0cb0 \u0c86\u0cb0\u0c82\u0cad\u0cbf\u0cb8\u0cbf\u0ca6\u0cb0\u0cc6 \u0ca6\u0cbf\u0ca8\u0cb5\u0cc2 \u0c97\u0cb2\u0cbe\u0c9f\u0cc6-\u0c8f\u0cb0\u0cbf\u0cb3\u0cbf\u0ca4\u0c97\u0cb3\u0cbf\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6; \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9\u0cb5\u0cbe\u0ca6\u0cb0\u0cc6 \u0ca6\u0c82\u0caa\u0ca4\u0cbf\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0c85\u0cb8\u0ccd\u0ca5\u0cbf\u0cb0\u0ca4\u0cc6 \u0c87\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c86\u0ca6\u0ccd\u0ca6\u0cb0\u0cbf\u0c82\u0ca6 \u0cb6\u0cbe\u0cb6\u0ccd\u0cb5\u0ca4 \u0c95\u0cc6\u0cb2\u0cb8\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0c87\u0ca6\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca4\u0ccd\u0caf\u0c9c\u0cbf\u0cb8\u0cac\u0cc7\u0c95\u0cc1.",9),A.aM("\u0935\u093e\u0930\u0918\u094d\u0928\u093e \u091a \u0924\u093f\u0925\u093f\u0930\u094d\u092f\u0947\u0937\u093e\u0902 \u0924\u094d\u0930\u092f\u094b\u0926\u0936 \u0938\u092e\u0928\u094d\u0935\u093f\u0924\u093e\u0903 \u0964\n\u0915\u094d\u0930\u0915\u091a\u0903 \u0938 \u0924\u0941 \u0935\u093f\u091c\u094d\u091e\u0947\u092f\u0903 \u0938\u0930\u094d\u0935\u0915\u093e\u0930\u094d\u092f\u0935\u093f\u0928\u093e\u0936\u0915\u0903 \u0965 \u0967\u0966 \u0965","mc_1_10",'\u0cb5\u0cbe\u0cb0\u0ca6 \u0cb8\u0c82\u0c96\u0ccd\u0caf\u0cc6\u0c97\u0cc6 \u0caf\u0cbe\u0cb5 \u0ca4\u0cbf\u0ca5\u0cbf\u0caf\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb8\u0cc7\u0cb0\u0cbf\u0cb8\u0cbf\u0ca6\u0cb0\u0cc6 \u0c92\u0c9f\u0ccd\u0c9f\u0cc1 \u0cae\u0cca\u0ca4\u0ccd\u0ca4 \u0ce7\u0ce9 \u0c86\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6\u0caf\u0ccb, \u0c85\u0ca6\u0cc1 "\u0c95\u0ccd\u0cb0\u0c95\u0c9a \u0caf\u0ccb\u0c97" \u0c8e\u0ca8\u0cbf\u0cb8\u0cbf\u0c95\u0cca\u0cb3\u0ccd\u0cb3\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c87\u0ca6\u0cc1 \u0c8e\u0cb2\u0ccd\u0cb2\u0cbe \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc2 \u0ca8\u0cbe\u0cb6 \u0cae\u0cbe\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.',"\u0cb5\u0cbe\u0cb0\u0c98\u0ccd\u0ca8\u0cbe \u0c9a \u0ca4\u0cbf\u0ca5\u0cbf\u0cb0\u0ccd\u0caf\u0cc7\u0cb7\u0cbe\u0c82 \u0ca4\u0ccd\u0cb0\u0caf\u0ccb\u0ca6\u0cb6 \u0cb8\u0cae\u0ca8\u0ccd\u0cb5\u0cbf\u0ca4\u0cbe\u0c83 \u0964\n\u0c95\u0ccd\u0cb0\u0c95\u0c9a\u0c83 \u0cb8 \u0ca4\u0cc1 \u0cb5\u0cbf\u0c9c\u0ccd\u0c9e\u0cc7\u0caf\u0c83 \u0cb8\u0cb0\u0ccd\u0cb5\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0cb5\u0cbf\u0ca8\u0cbe\u0cb6\u0c95\u0c83 \u0965 \u0ce7\u0ce6 \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0c95\u0ccd\u0cb0\u0c95\u0c9a - \u0c97\u0cb0\u0c97\u0cb8\u0ca6 \u0c92\u0cb3\u0ca8\u0ccb\u0c9f): '\u0c95\u0ccd\u0cb0\u0c95\u0c9a' \u0c8e\u0c82\u0ca6\u0cb0\u0cc6 \u0cae\u0cb0 \u0c95\u0cca\u0caf\u0ccd\u0caf\u0cc1\u0cb5 \u0c97\u0cb0\u0c97\u0cb8 (Saw). \u0c97\u0cb0\u0c97\u0cb8\u0cb5\u0cc1 \u0cb9\u0cc7\u0c97\u0cc6 \u0cb5\u0cb8\u0ccd\u0ca4\u0cc1\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c95\u0ca4\u0ccd\u0ca4\u0cb0\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6\u0caf\u0ccb, \u0cb9\u0cbe\u0c97\u0cc6\u0caf\u0cc7 \u0c88 \u0caf\u0ccb\u0c97\u0cb5\u0cc1 \u0ca8\u0cae\u0ccd\u0cae \u0cb6\u0ccd\u0cb0\u0cae\u0ca6 \u0cab\u0cb2\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c95\u0ca4\u0ccd\u0ca4\u0cb0\u0cbf\u0cb8\u0cbf \u0ca8\u0cbf\u0cb0\u0cb0\u0ccd\u0ca5\u0c95\u0c97\u0cca\u0cb3\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. (\u0cad\u0cbe\u0ca8\u0cc1\u0cb5\u0cbe\u0cb0-\u0ce7... \u0cb6\u0ca8\u0cbf\u0cb5\u0cbe\u0cb0-\u0ced; \u0caa\u0cbe\u0ca1\u0ccd\u0caf-\u0ce7... \u0c9a\u0ca4\u0cc1\u0cb0\u0ccd\u0ca6\u0cb6\u0cbf-\u0ce7\u0cea). \u0cb5\u0cbe\u0cb0\u0ca6 \u0cb8\u0c82\u0c96\u0ccd\u0caf\u0cc6 + \u0ca4\u0cbf\u0ca5\u0cbf\u0caf \u0cb8\u0c82\u0c96\u0ccd\u0caf\u0cc6 = \u0ce7\u0ce9 \u0cac\u0c82\u0ca6\u0cb0\u0cc6, \u0c86 \u0ce7\u0ce9 \u0c8e\u0c82\u0cac \u0cb8\u0c82\u0c96\u0ccd\u0caf\u0cc6 \u0c9c\u0ccd\u0caf\u0ccb\u0ca4\u0cbf\u0cb7\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0ca4\u0cc0\u0cb5\u0ccd\u0cb0 \u0c85\u0cb8\u0cae\u0ca4\u0ccb\u0cb2\u0ca8 \u0cb8\u0cc2\u0c9a\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c89\u0ca6\u0cbe: \u0cb6\u0cc1\u0c95\u0ccd\u0cb0\u0cb5\u0cbe\u0cb0(\u0cec) + \u0cb8\u0caa\u0ccd\u0ca4\u0cae\u0cbf(\u0ced) = \u0ce7\u0ce9. \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9, \u0cb5\u0ccd\u0caf\u0cb5\u0cb9\u0cbe\u0cb0\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0cb8\u0c82\u0cac\u0c82\u0ca7\u0c97\u0cb3\u0cc1 \u0ca4\u0cc1\u0c82\u0ca1\u0cbe\u0c97\u0cc1\u0cb5\u0cc1\u0ca6\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca4\u0ca1\u0cc6\u0caf\u0cb2\u0cc1 \u0c87\u0ca6\u0ca8\u0ccd\u0ca8\u0cc1 \u0cac\u0cbf\u0ca1\u0cb2\u0cc7\u0cac\u0cc7\u0c95\u0cc1.",10),A.aM("\u0938\u094d\u0935\u0930\u094d\u0917\u0947 \u092d\u0926\u094d\u0930\u093e \u0936\u0941\u092d\u0902 \u0915\u0941\u0930\u094d\u092f\u093e\u0924\u094d \u092a\u093e\u0924\u093e\u0932\u0947 \u091a \u0927\u0928\u093e\u0917\u092e\u092e\u094d \u0964\n\u092e\u0930\u094d\u0924\u094d\u092f\u0932\u094b\u0915\u0947 \u092f\u0926\u093e \u092d\u0926\u094d\u0930\u093e \u0938\u0930\u094d\u0935\u0915\u093e\u0930\u094d\u092f\u0935\u093f\u0928\u093e\u0936\u093f\u0928\u0940 \u0965 \u0967\u0967 \u0965","mc_1_11","\u0cad\u0ca6\u0ccd\u0cb0\u0cbe (\u0cb5\u0cbf\u0cb7\u0ccd\u0c9f\u0cbf \u0c95\u0cb0\u0ca3) \u0cb8\u0ccd\u0cb5\u0cb0\u0ccd\u0c97\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf\u0cb0\u0cc1\u0cb5\u0cbe\u0c97 \u0cb6\u0cc1\u0cad\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6, \u0caa\u0cbe\u0ca4\u0cbe\u0cb3\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf\u0cb0\u0cc1\u0cb5\u0cbe\u0c97 \u0cb9\u0ca3\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 (\u0c86\u0cb0\u0ccd\u0ca5\u0cbf\u0c95 \u0cb2\u0cbe\u0cad) \u0ca4\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c86\u0ca6\u0cb0\u0cc6 \u0cad\u0cc2\u0cb2\u0ccb\u0c95\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf (\u0cae\u0cb0\u0ccd\u0ca4\u0ccd\u0caf\u0cb2\u0ccb\u0c95) \u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0c87\u0ca6\u0ccd\u0ca6\u0cbe\u0c97 \u0c85\u0ca6\u0cc1 \u0c8e\u0cb2\u0ccd\u0cb2\u0cbe \u0cb6\u0cc1\u0cad \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca8\u0cbe\u0cb6\u0cae\u0cbe\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.","\u0cb8\u0ccd\u0cb5\u0cb0\u0ccd\u0c97\u0cc7 \u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0cb6\u0cc1\u0cad\u0c82 \u0c95\u0cc1\u0cb0\u0ccd\u0caf\u0cbe\u0ca4\u0ccd \u0caa\u0cbe\u0ca4\u0cbe\u0cb2\u0cc7 \u0c9a \u0ca7\u0ca8\u0cbe\u0c97\u0cae\u0cae\u0ccd \u0964\n\u0cae\u0cb0\u0ccd\u0ca4\u0ccd\u0caf\u0cb2\u0ccb\u0c95\u0cc7 \u0caf\u0ca6\u0cbe \u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0cb8\u0cb0\u0ccd\u0cb5\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0cb5\u0cbf\u0ca8\u0cbe\u0cb6\u0cbf\u0ca8\u0cc0 \u0965 \u0ce7\u0ce7 \u0965","\u0cae\u0cc2\u0cb2 \u0c97\u0ccd\u0cb0\u0c82\u0ca5\u0ca6 \u0cb5\u0cbf\u0cb6\u0cc7\u0cb7 \u0c85\u0cb0\u0ccd\u0ca5 (\u0caa\u0cc0\u0caf\u0cc2\u0cb7\u0ca7\u0cbe\u0cb0\u0cbe): \u0cad\u0ca6\u0ccd\u0cb0\u0cc6\u0caf \u0ca6\u0cbf\u0c95\u0ccd\u0c95\u0cc1 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb5\u0cbe\u0cb8\u0cb8\u0ccd\u0ca5\u0cbe\u0ca8\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c9a\u0c82\u0ca6\u0ccd\u0cb0\u0ca8 \u0cb0\u0cbe\u0cb6\u0cbf\u0caf\u0cbf\u0c82\u0ca6 \u0ca8\u0cbf\u0cb0\u0ccd\u0ca3\u0caf\u0cbf\u0cb8\u0cb2\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c9a\u0c82\u0ca6\u0ccd\u0cb0\u0ca8\u0cc1 \u0cae\u0cc7\u0cb7, \u0cb5\u0cc3\u0cb7\u0cad, \u0cae\u0cbf\u0ca5\u0cc1\u0ca8 \u0c85\u0ca5\u0cb5\u0cbe \u0cb5\u0cc3\u0cb6\u0ccd\u0c9a\u0cbf\u0c95 \u0cb0\u0cbe\u0cb6\u0cbf\u0caf\u0cb2\u0ccd\u0cb2\u0cbf\u0ca6\u0ccd\u0ca6\u0cbe\u0c97 \u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0cb8\u0ccd\u0cb5\u0cb0\u0ccd\u0c97\u0ca6\u0cb2\u0ccd\u0cb2\u0cc2; \u0c95\u0ca8\u0ccd\u0caf\u0cbe, \u0ca4\u0cc1\u0cb2\u0cbe, \u0ca7\u0ca8\u0cc1\u0cb8\u0ccd\u0cb8\u0cc1, \u0cae\u0c95\u0cb0\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf\u0ca6\u0ccd\u0ca6\u0cbe\u0c97 \u0caa\u0cbe\u0ca4\u0cbe\u0cb3\u0ca6\u0cb2\u0ccd\u0cb2\u0cc2; \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c95\u0cb0\u0ccd\u0c95\u0cbe\u0c9f\u0c95, \u0cb8\u0cbf\u0c82\u0cb9, \u0c95\u0cc1\u0c82\u0cad, \u0cae\u0cc0\u0ca8 \u0cb0\u0cbe\u0cb6\u0cbf\u0caf\u0cb2\u0ccd\u0cb2\u0cbf\u0ca6\u0ccd\u0ca6\u0cbe\u0c97 \u0cae\u0cb0\u0ccd\u0ca4\u0ccd\u0caf\u0cb2\u0ccb\u0c95\u0ca6\u0cb2\u0ccd\u0cb2\u0cc2 (\u0cad\u0cc2\u0cae\u0cbf\u0caf \u0cae\u0cc7\u0cb2\u0cc6) \u0c87\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0cbe\u0cb3\u0cc6. \u0cad\u0cc2\u0cae\u0cbf\u0caf \u0cae\u0cc7\u0cb2\u0cc6 \u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0c87\u0ca6\u0ccd\u0ca6\u0cb0\u0cc6, \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9, \u0c97\u0cc3\u0cb9\u0caa\u0ccd\u0cb0\u0cb5\u0cc7\u0cb6 \u0cae\u0cc1\u0c82\u0ca4\u0cbe\u0ca6 \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cac\u0cbe\u0cb0\u0ca6\u0cc1. \u0c86\u0ca6\u0cb0\u0cc6 \u0cb8\u0ccd\u0cb5\u0cb0\u0ccd\u0c97 \u0c85\u0ca5\u0cb5\u0cbe \u0caa\u0cbe\u0ca4\u0cbe\u0cb3\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf\u0cb0\u0cc1\u0cb5\u0cbe\u0c97 \u0cad\u0ca6\u0ccd\u0cb0\u0cc6\u0caf\u0cc1 \u0c85\u0cb6\u0cc1\u0cad\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c89\u0c82\u0c9f\u0cc1\u0cae\u0cbe\u0ca1\u0cc1\u0cb5\u0cc1\u0ca6\u0cbf\u0cb2\u0ccd\u0cb2, \u0cac\u0ca6\u0cb2\u0cbe\u0c97\u0cbf \u0c92\u0cb3\u0cbf\u0ca4\u0ca8\u0ccd\u0ca8\u0cc7 \u0cae\u0cbe\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0cbe\u0cb3\u0cc6 \u0c8e\u0c82\u0ca6\u0cc1 \u0c97\u0ccd\u0cb0\u0c82\u0ca5\u0c95\u0cbe\u0cb0\u0cb0\u0cc1 \u0cb8\u0cc2\u0c95\u0ccd\u0cb7\u0ccd\u0cae\u0cb5\u0cbe\u0c97\u0cbf \u0cb5\u0cbf\u0cb5\u0cb0\u0cbf\u0cb8\u0cbf\u0ca6\u0ccd\u0ca6\u0cbe\u0cb0\u0cc6.",11),A.aM("\u092d\u0926\u094d\u0930\u093e\u092a\u0941\u091a\u094d\u091b\u0947 \u0936\u0941\u092d\u0902 \u0935\u093f\u0926\u094d\u092f\u093e\u0926\u094d \u092d\u0926\u094d\u0930\u093e\u0938\u094d\u092f\u0947 \u0915\u093e\u0930\u094d\u092f\u0928\u093e\u0936\u0928\u092e\u094d \u0964\n\u0909\u0924\u094d\u0924\u0930\u093e\u0930\u094d\u0927\u0947 \u0924\u0941 \u092d\u0926\u094d\u0930\u093e\u092f\u093e\u0903 \u0915\u0930\u094d\u0924\u0935\u094d\u092f\u0902 \u0936\u0941\u092d\u092e\u093e\u091a\u0930\u0947\u0924\u094d \u0965 \u0967\u0968 \u0965","mc_1_12","\u0cad\u0ca6\u0ccd\u0cb0\u0cc6\u0caf \u0cae\u0cc1\u0c96 \u0cad\u0cbe\u0c97\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf \u0cae\u0cbe\u0ca1\u0cbf\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca8\u0cbe\u0cb6\u0c97\u0cca\u0cb3\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0cad\u0ca6\u0ccd\u0cb0\u0cc6\u0caf \u0caa\u0cc1\u0c9a\u0ccd\u0c9b\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf (\u0cac\u0cbe\u0cb2\u0ca6 \u0cad\u0cbe\u0c97) \u0c85\u0ca5\u0cb5\u0cbe \u0cad\u0ca6\u0ccd\u0cb0\u0cc6\u0caf \u0c89\u0ca4\u0ccd\u0ca4\u0cb0\u0cbe\u0cb0\u0ccd\u0ca7\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf (\u0c95\u0cca\u0ca8\u0cc6\u0caf \u0cad\u0cbe\u0c97\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf) \u0cb6\u0cc1\u0cad \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cac\u0cb9\u0cc1\u0ca6\u0cc1 \u0c8e\u0c82\u0ca6\u0cc1 \u0ca4\u0cbf\u0cb3\u0cbf\u0caf\u0cac\u0cc7\u0c95\u0cc1.","\u0cad\u0ca6\u0ccd\u0cb0\u0cbe\u0caa\u0cc1\u0c9a\u0ccd\u0c9b\u0cc7 \u0cb6\u0cc1\u0cad\u0c82 \u0cb5\u0cbf\u0ca6\u0ccd\u0caf\u0cbe\u0ca6\u0ccd \u0cad\u0ca6\u0ccd\u0cb0\u0cbe\u0cb8\u0ccd\u0caf\u0cc7 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0ca8\u0cbe\u0cb6\u0ca8\u0cae\u0ccd \u0964\n\u0c89\u0ca4\u0ccd\u0ca4\u0cb0\u0cbe\u0cb0\u0ccd\u0ca7\u0cc7 \u0ca4\u0cc1 \u0cad\u0ca6\u0ccd\u0cb0\u0cbe\u0caf\u0cbe\u0c83 \u0c95\u0cb0\u0ccd\u0ca4\u0cb5\u0ccd\u0caf\u0c82 \u0cb6\u0cc1\u0cad\u0cae\u0cbe\u0c9a\u0cb0\u0cc7\u0ca4\u0ccd \u0965 \u0ce7\u0ce8 \u0965","\u0cb5\u0cbf\u0cb6\u0cc7\u0cb7 \u0cb0\u0cb9\u0cb8\u0ccd\u0caf\u0cbe\u0cb0\u0ccd\u0ca5: \u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4 \u0c9a\u0cbf\u0c82\u0ca4\u0cbe\u0cae\u0ca3\u0cbf\u0caf \u0caa\u0ccd\u0cb0\u0c95\u0cbe\u0cb0 \u0cad\u0ca6\u0ccd\u0cb0\u0cbe (\u0cb5\u0cbf\u0cb7\u0ccd\u0c9f\u0cbf \u0c95\u0cb0\u0ca3) \u0cb8\u0c82\u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cb5\u0cbe\u0c97\u0cbf \u0c95\u0cc6\u0c9f\u0ccd\u0c9f\u0ca6\u0ccd\u0ca6\u0cb2\u0ccd\u0cb2. \u0cad\u0ca6\u0ccd\u0cb0\u0cc6\u0caf \u0c92\u0c9f\u0ccd\u0c9f\u0cc1 \u0c97\u0cb3\u0cbf\u0c97\u0cc6\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf, \u0cae\u0cca\u0ca6\u0cb2 \u0ceb \u0c97\u0cb3\u0cbf\u0c97\u0cc6\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 '\u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0cae\u0cc1\u0c96' \u0c8e\u0ca8\u0ccd\u0ca8\u0cc1\u0ca4\u0ccd\u0ca4\u0cbe\u0cb0\u0cc6 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c85\u0ca6\u0cc1 \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0c95\u0ccd\u0cb0\u0cc2\u0cb0. \u0ca8\u0c82\u0ca4\u0cb0 \u0cac\u0cb0\u0cc1\u0cb5 \u0c95\u0c82\u0ca0, \u0cb9\u0cc3\u0ca6\u0caf \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0ca8\u0cbe\u0cad\u0cbf \u0cad\u0cbe\u0c97\u0c97\u0cb3\u0cc2 \u0c85\u0cb6\u0cc1\u0cad\u0cb5\u0cc7. \u0c86\u0ca6\u0cb0\u0cc6, \u0cad\u0ca6\u0ccd\u0cb0\u0cc6\u0caf \u0c95\u0cca\u0ca8\u0cc6\u0caf \u0ce9 \u0c97\u0cb3\u0cbf\u0c97\u0cc6\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 '\u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0caa\u0cc1\u0c9a\u0ccd\u0c9b' \u0c8e\u0ca8\u0ccd\u0ca8\u0cc1\u0ca4\u0ccd\u0ca4\u0cbe\u0cb0\u0cc6. \u0ca4\u0cc0\u0cb0\u0cbe \u0c85\u0ca8\u0cbf\u0cb5\u0cbe\u0cb0\u0ccd\u0caf\u0cac\u0cbf\u0ca6\u0ccd\u0ca6\u0cb0\u0cc6, \u0cad\u0ca6\u0ccd\u0cb0\u0cbe \u0caa\u0cc1\u0c9a\u0ccd\u0c9b\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0c9c\u0cbe\u0c97\u0cb0\u0cc2\u0c95\u0ca4\u0cc6\u0caf\u0cbf\u0c82\u0ca6 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cac\u0cb9\u0cc1\u0ca6\u0cc1 \u0c8e\u0c82\u0ca6\u0cc1 \u0cb6\u0cbe\u0cb8\u0ccd\u0ca4\u0ccd\u0cb0\u0cb5\u0cc1 \u0c92\u0c82\u0ca6\u0cc1 \u0cb5\u0cbf\u0cb6\u0cc7\u0cb7 \u0cb0\u0cbf\u0caf\u0cbe\u0caf\u0cbf\u0ca4\u0cbf (Exception rule) \u0ca8\u0cc0\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.",12),A.aM("\u0930\u0947\u0935\u0924\u094d\u092f\u0936\u094d\u0935\u093f\u0928\u092f\u094b\u0903 \u0938\u0928\u094d\u0927\u094c \u0938\u093e\u0930\u094d\u092a\u092a\u093f\u0924\u094d\u0930\u094d\u092f\u094b\u0938\u094d\u0924\u0925\u0948\u0935 \u091a \u0964\n\u091c\u094d\u092f\u0947\u0937\u094d\u0920\u093e\u0917\u0923\u094d\u0921\u093e\u0928\u094d\u0924\u092f\u094b\u0903 \u0938\u0928\u094d\u0927\u094c \u0938\u0930\u094d\u0935\u0915\u093e\u0930\u094d\u092f\u0902 \u0935\u093f\u0935\u0930\u094d\u091c\u092f\u0947\u0924\u094d \u0965 \u0967\u0969 \u0965","mc_1_13","\u0cb0\u0cc7\u0cb5\u0ca4\u0cbf-\u0c85\u0cb6\u0ccd\u0cb5\u0cbf\u0ca8\u0cbf \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0ca6 \u0cb8\u0c82\u0ca7\u0cbf, \u0c86\u0cb6\u0ccd\u0cb2\u0cc7\u0cb7\u0cbe (\u0cb8\u0cbe\u0cb0\u0ccd\u0caa)-\u0cae\u0c96\u0cbe (\u0caa\u0cbf\u0ca4\u0ccd\u0cb0\u0ccd\u0caf) \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0ca6 \u0cb8\u0c82\u0ca7\u0cbf, \u0cb9\u0cbe\u0c97\u0cc2 \u0c9c\u0ccd\u0caf\u0cc7\u0cb7\u0ccd\u0ca0\u0cbe-\u0cae\u0cc2\u0cb2\u0cbe \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0c97\u0cb3 \u0cb8\u0c82\u0ca7\u0cbf \u0c95\u0cbe\u0cb2\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 '\u0c97\u0c82\u0ca1\u0cbe\u0c82\u0ca4' \u0c8e\u0ca8\u0ccd\u0ca8\u0cc1\u0ca4\u0ccd\u0ca4\u0cbe\u0cb0\u0cc6. \u0c88 \u0cb8\u0cae\u0caf\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0c8e\u0cb2\u0ccd\u0cb2 \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cac\u0cbf\u0ca1\u0cac\u0cc7\u0c95\u0cc1.","\u0cb0\u0cc7\u0cb5\u0ca4\u0ccd\u0caf\u0cb6\u0ccd\u0cb5\u0cbf\u0ca8\u0caf\u0ccb\u0c83 \u0cb8\u0c82\u0ca7\u0ccc \u0cb8\u0cbe\u0cb0\u0ccd\u0caa\u0caa\u0cbf\u0ca4\u0ccd\u0cb0\u0ccd\u0caf\u0ccb\u0cb8\u0ccd\u0ca4\u0ca5\u0cc8\u0cb5 \u0c9a \u0964\n\u0c9c\u0ccd\u0caf\u0cc7\u0cb7\u0ccd\u0ca0\u0cbe\u0c97\u0c82\u0ca1\u0cbe\u0c82\u0ca4\u0caf\u0ccb\u0c83 \u0cb8\u0c82\u0ca7\u0ccc \u0cb8\u0cb0\u0ccd\u0cb5\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c82 \u0cb5\u0cbf\u0cb5\u0cb0\u0ccd\u0c9c\u0caf\u0cc7\u0ca4\u0ccd \u0965 \u0ce7\u0ce9 \u0965","\u0c86\u0cb3\u0cb5\u0cbe\u0ca6 \u0c85\u0cb0\u0ccd\u0ca5\u0ca6 \u0cb5\u0cbf\u0cb6\u0ccd\u0cb2\u0cc7\u0cb7\u0ca3\u0cc6: \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0 \u0cae\u0c82\u0ca1\u0cb2\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0c9c\u0cb2\u0cb0\u0cbe\u0cb6\u0cbf (\u0c95\u0cb0\u0ccd\u0c95, \u0cb5\u0cc3\u0cb6\u0ccd\u0c9a\u0cbf\u0c95, \u0cae\u0cc0\u0ca8) \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c85\u0c97\u0ccd\u0ca8\u0cbf\u0cb0\u0cbe\u0cb6\u0cbf\u0c97\u0cb3\u0cc1 (\u0cb8\u0cbf\u0c82\u0cb9, \u0ca7\u0ca8\u0cc1, \u0cae\u0cc7\u0cb7) \u0c95\u0cc2\u0ca1\u0cc1\u0cb5 \u0cb8\u0ccd\u0ca5\u0cb3\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c97\u0c82\u0ca1\u0cbe\u0c82\u0ca4 (\u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0c85\u0caa\u0cbe\u0caf\u0c95\u0cbe\u0cb0\u0cbf \u0c97\u0c82\u0c9f\u0cc1 \u0c85\u0ca5\u0cb5\u0cbe \u0cb8\u0c82\u0ca7\u0cbf) \u0c8e\u0c82\u0ca6\u0cc1 \u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8\u0cbf\u0cb8\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6. \u0cb0\u0cc7\u0cb5\u0ca4\u0cbf-\u0c85\u0cb6\u0ccd\u0cb5\u0cbf\u0ca8\u0cbf \u0ce7 \u0c97\u0cb3\u0cbf\u0c97\u0cc6, \u0c86\u0cb6\u0ccd\u0cb2\u0cc7\u0cb7\u0cbe-\u0cae\u0c96\u0cbe \u0ce8 \u0c97\u0cb3\u0cbf\u0c97\u0cc6, \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c9c\u0ccd\u0caf\u0cc7\u0cb7\u0ccd\u0ca0\u0cbe-\u0cae\u0cc2\u0cb2\u0cbe \u0ce7 \u0c97\u0cb3\u0cbf\u0c97\u0cc6\u0c97\u0cb3 \u0c97\u0c82\u0ca1\u0cbe\u0c82\u0ca4\u0cb5\u0cc1 \u0c9c\u0ca8\u0cbf\u0cb8\u0cbf\u0ca6 \u0cae\u0c97\u0cc1\u0cb5\u0cbf\u0c97\u0cc2, \u0caa\u0ccb\u0cb7\u0c95\u0cb0\u0cbf\u0c97\u0cc2, \u0cb9\u0cbe\u0c97\u0cc2 \u0c87\u0ca1\u0cc0 \u0cb5\u0c82\u0cb6\u0c95\u0ccd\u0c95\u0cc2 \u0cae\u0cbe\u0cb0\u0c95\u0cb5\u0cbe\u0c97\u0cac\u0cb9\u0cc1\u0ca6\u0cc1. \u0c97\u0c82\u0ca1\u0cbe\u0c82\u0ca4 \u0ca6\u0ccb\u0cb7 \u0caa\u0cb0\u0cbf\u0cb9\u0cbe\u0cb0\u0c95\u0ccd\u0c95\u0cc6 \u0cb5\u0cbf\u0cb6\u0cc7\u0cb7 \u0cb6\u0cbe\u0c82\u0ca4\u0cbf-\u0cb9\u0ccb\u0cae\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0ca6\u0cc7 \u0cae\u0cc1\u0c82\u0ca6\u0cbf\u0ca8 \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf \u0cae\u0cbe\u0ca1\u0cac\u0cbe\u0cb0\u0ca6\u0cc1.",13),A.aM("\u0927\u0928\u093f\u0937\u094d\u0920\u093e\u092a\u091e\u094d\u091a\u0915\u0902 \u092a\u094d\u0930\u093e\u092a\u094d\u0924\u0947 \u0926\u0915\u094d\u0937\u093f\u0923\u093e\u092f\u0928\u0917\u0947 \u0939\u0930\u094c \u0964\n\u0935\u093f\u0935\u093e\u0939\u0902 \u0935\u0930\u094d\u091c\u092f\u0947\u0924\u094d \u0927\u0940\u092e\u093e\u0928\u094d \u0917\u0943\u0939\u093e\u0930\u092e\u094d\u092d\u0902 \u091a \u0935\u0930\u094d\u091c\u092f\u0947\u0924\u094d \u0965 \u0967\u096a \u0965","mc_1_14","\u0ca7\u0ca8\u0cbf\u0cb7\u0ccd\u0ca0\u0cbe \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0ca6 \u0c95\u0cca\u0ca8\u0cc6\u0caf \u0c8e\u0cb0\u0ca1\u0cc1 \u0caa\u0cbe\u0ca6\u0c97\u0cb3\u0cbf\u0c82\u0ca6 \u0cb9\u0cbf\u0ca1\u0cbf\u0ca6\u0cc1 \u0cb6\u0ca4\u0cad\u0cbf\u0cb7, \u0caa\u0cc2\u0cb0\u0ccd\u0cb5\u0cbe\u0cad\u0cbe\u0ca6\u0ccd\u0cb0, \u0c89\u0ca4\u0ccd\u0ca4\u0cb0\u0cbe\u0cad\u0cbe\u0ca6\u0ccd\u0cb0 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb0\u0cc7\u0cb5\u0ca4\u0cc0 \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0c97\u0cb3\u0cb5\u0cb0\u0cc6\u0c97\u0cc6 \u0cac\u0cb0\u0cc1\u0cb5 \u0c90\u0ca6\u0cc1 \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 (\u0caa\u0c82\u0c9a\u0c95) \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c97\u0cc3\u0cb9\u0ca8\u0cbf\u0cb0\u0ccd\u0cae\u0cbe\u0ca3\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cac\u0cc1\u0ca6\u0ccd\u0ca7\u0cbf\u0cb5\u0c82\u0ca4\u0ca8\u0cbe\u0ca6\u0cb5\u0ca8\u0cc1 \u0cb5\u0cb0\u0ccd\u0c9c\u0cbf\u0cb8\u0cac\u0cc7\u0c95\u0cc1.","\u0ca7\u0ca8\u0cbf\u0cb7\u0ccd\u0ca0\u0cbe\u0caa\u0c82\u0c9a\u0c95\u0c82 \u0caa\u0ccd\u0cb0\u0cbe\u0caa\u0ccd\u0ca4\u0cc7 \u0ca6\u0c95\u0ccd\u0cb7\u0cbf\u0ca3\u0cbe\u0caf\u0ca8\u0c97\u0cc7 \u0cb9\u0cb0\u0ccc \u0964\n\u0cb5\u0cbf\u0cb5\u0cbe\u0cb9\u0c82 \u0cb5\u0cb0\u0ccd\u0c9c\u0caf\u0cc7\u0ca4\u0ccd \u0ca7\u0cc0\u0cae\u0cbe\u0ca8\u0ccd \u0c97\u0cc3\u0cb9\u0cbe\u0cb0\u0c82\u0cad\u0c82 \u0c9a \u0cb5\u0cb0\u0ccd\u0c9c\u0caf\u0cc7\u0ca4\u0ccd \u0965 \u0ce7\u0cea \u0965","\u0cb6\u0cbe\u0cb8\u0ccd\u0ca4\u0ccd\u0cb0\u0cc0\u0caf \u0c92\u0cb3\u0ca8\u0ccb\u0c9f: \u0caa\u0c82\u0c9a\u0c95 \u0c85\u0c82\u0ca6\u0cb0\u0cc6 \u0c90\u0ca6\u0cb0 \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0 \u0cb8\u0cae\u0cc2\u0cb9 (\u0ca7\u0ca8\u0cbf\u0cb7\u0ccd\u0ca0\u0cbe\u0ca6\u0ccd\u0cb5\u0cbf\u0ca4\u0cc0\u0caf\u0cbe\u0cb0\u0ccd\u0ca7\u0ca6\u0cbf\u0c82\u0ca6 \u0cb0\u0cc7\u0cb5\u0ca4\u0cbf\u0cb5\u0cb0\u0cc6\u0c97\u0cc6). \u0caa\u0c82\u0c9a\u0c95\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0ca6\u0c95\u0ccd\u0cb7\u0cbf\u0ca3 \u0ca6\u0cbf\u0c95\u0ccd\u0c95\u0cbf\u0c97\u0cc6 \u0caa\u0ccd\u0cb0\u0caf\u0cbe\u0ca3, \u0cae\u0cb0 \u0c95\u0ca1\u0cbf\u0caf\u0cc1\u0cb5\u0cc1\u0ca6\u0cc1, \u0cae\u0ca8\u0cc6\u0c97\u0cc6 \u0c9a\u0cbe\u0cb5\u0ca3\u0cbf \u0cb9\u0cbe\u0c95\u0cc1\u0cb5\u0cc1\u0ca6\u0cc1 (\u0ca4\u0cbe\u0cb0\u0cb8\u0cbf), \u0cb6\u0cb5\u0cb8\u0c82\u0cb8\u0ccd\u0c95\u0cbe\u0cb0 \u0c87\u0cb5\u0cc1\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cbf\u0ca6\u0cb0\u0cc6 \u0ca4\u0cca\u0c82\u0ca6\u0cb0\u0cc6\u0c97\u0cb3\u0cc1 \u0c90\u0ca6\u0cc1 \u0caa\u0c9f\u0ccd\u0c9f\u0cc1 (\u0ceb \u0c97\u0cc1\u0ca3) \u0cb9\u0cc6\u0c9a\u0ccd\u0c9a\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6 (\u0c92\u0cac\u0ccd\u0cac \u0cb8\u0ca4\u0ccd\u0ca4\u0cb0\u0cc6 \u0ceb \u0cb8\u0cbe\u0cb5\u0cc1 \u0cac\u0cb0\u0cac\u0cb9\u0cc1\u0ca6\u0cc6\u0c82\u0cac \u0ca8\u0c82\u0cac\u0cbf\u0c95\u0cc6). \u0c86\u0ca6\u0cb0\u0cc6, \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9, \u0cae\u0cc1\u0c82\u0c9c\u0cbf\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0c95\u0cc6\u0cb2\u0cb5\u0cc1 \u0ca8\u0cbf\u0cb0\u0ccd\u0ca6\u0cbf\u0cb7\u0ccd\u0c9f \u0caa\u0c82\u0c9a\u0c95 \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0c97\u0cb3\u0cc1 (\u0c89\u0ca6\u0cbe: \u0c89\u0ca4\u0ccd\u0ca4\u0cb0\u0cbe\u0cad\u0cbe\u0ca6\u0ccd\u0cb0, \u0cb0\u0cc7\u0cb5\u0ca4\u0cc0) \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0cb6\u0cc1\u0cad\u0cb5\u0cc6\u0c82\u0ca6\u0cc6\u0ca8\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6. \u0c86\u0ca6\u0ccd\u0ca6\u0cb0\u0cbf\u0c82\u0ca6 \u0cb8\u0c82\u0caa\u0cc2\u0cb0\u0ccd\u0ca3 \u0caa\u0c82\u0c9a\u0c95\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c95\u0cc1\u0cb0\u0cc1\u0ca1\u0cbe\u0c97\u0cbf \u0ca4\u0ccd\u0caf\u0c9c\u0cbf\u0cb8\u0cac\u0cbe\u0cb0\u0ca6\u0cc1; \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0ca6 \u0cb8\u0ccd\u0cb5\u0cb0\u0cc2\u0caa \u0c85\u0cb0\u0ccd\u0ca5\u0cae\u0cbe\u0ca1\u0cbf\u0c95\u0cca\u0c82\u0ca1\u0cc1 \u0cb5\u0cbf\u0cb5\u0cc7\u0c9a\u0ca8\u0cc6 \u0cac\u0cb3\u0cb8\u0cac\u0cc7\u0c95\u0cc1.",14),A.aM("\u091c\u0940\u0935\u0947 \u092d\u093e\u0930\u094d\u0917\u0935\u092f\u094b\u0930\u094d\u092e\u0942\u0922\u0947 \u092c\u093e\u0932\u0947 \u0935\u0943\u0926\u094d\u0927\u0947 \u091a \u0935\u093e\u0930\u0941\u0923\u0947 \u0964\n\u0938\u093f\u0902\u0939\u0938\u094d\u0925\u0947 \u0935\u0943\u0939\u0938\u094d\u092a\u0924\u094c \u091a \u0936\u0941\u092d\u0915\u0930\u094d\u092e \u0935\u093f\u0935\u0930\u094d\u091c\u092f\u0947\u0924\u094d \u0965 \u0967\u096b \u0965","mc_1_15","\u0c97\u0cc1\u0cb0\u0cc1 (\u0c9c\u0cc0\u0cb5) \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb6\u0cc1\u0c95\u0ccd\u0cb0\u0cb0\u0cc1 (\u0cad\u0cbe\u0cb0\u0ccd\u0c97\u0cb5) \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8\u0cbf\u0c82\u0ca6 \u0c85\u0cb8\u0ccd\u0ca4\u0c82\u0c97\u0ca4\u0cb0\u0cbe\u0ca6\u0cbe\u0c97 (\u0cae\u0cc2\u0ca2), \u0c89\u0ca6\u0caf\u0ca6 \u0ca8\u0c82\u0ca4\u0cb0 \u0cac\u0cbe\u0cb2\u0c95\u0cb0\u0cbe\u0c97\u0cbf\u0ca6\u0ccd\u0ca6\u0cbe\u0c97, \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c85\u0cb8\u0ccd\u0ca4\u0ca6 \u0cae\u0cca\u0ca6\u0cb2\u0cc1 \u0cb5\u0cc3\u0ca6\u0ccd\u0ca7\u0cb0\u0cbe\u0ca6\u0cbe\u0c97, \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c97\u0cc1\u0cb0\u0cc1-\u0cb8\u0cbf\u0c82\u0cb9 \u0cb0\u0cbe\u0cb6\u0cbf\u0caf\u0cb2\u0ccd\u0cb2\u0cbf\u0ca6\u0ccd\u0ca6\u0cbe\u0c97, \u0c8e\u0cb2\u0ccd\u0cb2 \u0cb6\u0cc1\u0cad \u0c95\u0cb0\u0ccd\u0cae\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca4\u0ccd\u0caf\u0c9c\u0cbf\u0cb8\u0cac\u0cc7\u0c95\u0cc1.","\u0c9c\u0cc0\u0cb5\u0cc7 \u0cad\u0cbe\u0cb0\u0ccd\u0c97\u0cb5\u0caf\u0ccb\u0cb0\u0ccd\u0cae\u0cc2\u0ca2\u0cc7 \u0cac\u0cbe\u0cb2\u0cc7 \u0cb5\u0cc3\u0ca6\u0ccd\u0ca7\u0cc7 \u0c9a \u0cb5\u0cbe\u0cb0\u0cc1\u0ca3\u0cc7 \u0964\n\u0cb8\u0cbf\u0c82\u0cb9\u0cb8\u0ccd\u0ca5\u0cc7 \u0cb5\u0cc3\u0cb9\u0cb8\u0ccd\u0caa\u0ca4\u0ccc \u0c9a \u0cb6\u0cc1\u0cad\u0c95\u0cb0\u0ccd\u0cae \u0cb5\u0cbf\u0cb5\u0cb0\u0ccd\u0c9c\u0caf\u0cc7\u0ca4\u0ccd \u0965 \u0ce7\u0ceb \u0965","\u0cac\u0cc3\u0cb9\u0ca4\u0ccd \u0cb0\u0cb9\u0cb8\u0ccd\u0caf (\u0cae\u0ccc\u0cb2\u0cbf\u0c95 \u0cb5\u0cbf\u0cb6\u0ccd\u0cb2\u0cc7\u0cb7\u0ca3\u0cc6): \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9, \u0c9a\u0ccc\u0cb2, \u0c89\u0caa\u0ca8\u0caf\u0ca8\u0c97\u0cb3 \u0caf\u0cb6\u0cb8\u0ccd\u0cb8\u0cbf\u0c97\u0cc6 \u0c97\u0cc1\u0cb0\u0cc1 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb6\u0cc1\u0c95\u0ccd\u0cb0 \u0cac\u0cb2\u0cb5\u0cc7 \u0caa\u0ccd\u0cb0\u0cbe\u0ca3. \u0c97\u0cc1\u0cb0\u0cc1 \u0c9c\u0ccd\u0c9e\u0cbe\u0ca8 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb8\u0c82\u0ca4\u0cbe\u0ca8\u0c95\u0cbe\u0cb0\u0c95 (\u0caa\u0cc1\u0cb0\u0cc1\u0cb7\u0cb0\u0cbf\u0c97\u0cc6), \u0cb6\u0cc1\u0c95\u0ccd\u0cb0 \u0caa\u0ccd\u0cb0\u0cc0\u0ca4\u0cbf \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c95\u0cb3\u0ca4\u0ccd\u0cb0\u0c95\u0cbe\u0cb0\u0c95 (\u0cb8\u0ccd\u0ca4\u0ccd\u0cb0\u0cc0\u0caf\u0cb0\u0cbf\u0c97\u0cc6). \u0c87\u0cb5\u0cb0\u0cc1 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8 \u0cac\u0cb3\u0cbf \u0cac\u0c82\u0ca6\u0cc1 \u0cae\u0cc2\u0ca2\u0cb0\u0cbe\u0ca6\u0cbe\u0c97 (\u0c85\u0cb8\u0ccd\u0ca4), \u0c85\u0cb5\u0cb0 \u0cb8\u0c82\u0caa\u0cc2\u0cb0\u0ccd\u0ca3 \u0cb6\u0c95\u0ccd\u0ca4\u0cbf \u0ca8\u0cb6\u0cbf\u0cb8\u0cbf\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c85\u0cb2\u0ccd\u0cb2\u0ca6\u0cc6, \u0c97\u0cc1\u0cb0\u0cc1\u0cb5\u0cbe\u0c97\u0cb2\u0cc0 \u0cb6\u0cc1\u0c95\u0ccd\u0cb0\u0ca8\u0cbe\u0c97\u0cb2\u0cc0 \u0c89\u0ca6\u0caf\u0cb5\u0cbe\u0ca6 \u0ca8\u0c82\u0ca4\u0cb0\u0ca6 \u0c95\u0cc6\u0cb2\u0cb5\u0cc1 \u0ca6\u0cbf\u0ca8\u0c97\u0cb3\u0cc1 (\u0cac\u0cbe\u0cb2\u0ca4\u0ccd\u0cb5 \u0ca6\u0ccb\u0cb7) \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c85\u0cb8\u0ccd\u0ca4\u0cb5\u0cbe\u0c97\u0cc1\u0cb5 \u0cb9\u0cbf\u0c82\u0ca6\u0cbf\u0ca8 \u0c95\u0cc6\u0cb2\u0cb5\u0cc1 \u0ca6\u0cbf\u0ca8\u0c97\u0cb3\u0cc1 (\u0cb5\u0cc3\u0ca6\u0ccd\u0ca7\u0ca4\u0ccd\u0cb5 \u0ca6\u0ccb\u0cb7) \u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0cb9\u0cc0\u0ca8\u0cb0\u0cc1. \u0c87\u0ca6\u0cb0 \u0c9c\u0cca\u0ca4\u0cc6\u0c97\u0cc6, \u0c97\u0cc1\u0cb0\u0cc1\u0cb5\u0cc1 \u0cb8\u0cbf\u0c82\u0cb9 \u0cb0\u0cbe\u0cb6\u0cbf\u0caf\u0cb2\u0ccd\u0cb2\u0cbf\u0ca6\u0ccd\u0ca6\u0cbe\u0c97 (\u0cb8\u0cbf\u0c82\u0cb9\u0cb8\u0ccd\u0ca5 \u0c97\u0cc1\u0cb0\u0cc1), \u0c97\u0ccb\u0ca6\u0cbe\u0cb5\u0cb0\u0cbf \u0ca8\u0ca6\u0cbf\u0caf \u0ca6\u0c95\u0ccd\u0cb7\u0cbf\u0ca3 \u0cad\u0cbe\u0c97\u0ca6\u0cb5\u0cb0\u0cbf\u0c97\u0cc6 (\u0cae\u0cb9\u0cbe\u0cb0\u0cbe\u0cb7\u0ccd\u0c9f\u0ccd\u0cb0/\u0c95\u0cb0\u0ccd\u0ca8\u0cbe\u0c9f\u0c95\u0ca6 \u0c95\u0cc6\u0cb2\u0cb5\u0cc1 \u0cad\u0cbe\u0c97\u0c97\u0cb3\u0cc1) \u0cae\u0cbe\u0ca4\u0ccd\u0cb0 \u0ca6\u0ccb\u0cb7. \u0c86\u0ca6\u0ccd\u0ca6\u0cb0\u0cbf\u0c82\u0ca6 \u0ca6\u0cc7\u0cb6-\u0c95\u0cbe\u0cb2\u0c95\u0ccd\u0c95\u0cc6 \u0c85\u0ca8\u0cc1\u0c97\u0cc1\u0ca3\u0cb5\u0cbe\u0c97\u0cbf \u0ca6\u0ccb\u0cb7\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c85\u0ca8\u0ccd\u0cb5\u0caf\u0cbf\u0cb8\u0cac\u0cc7\u0c95\u0cc1 \u0c8e\u0c82\u0ca6\u0cc1 \u0c9f\u0cc0\u0c95\u0cbe\u0c95\u0cbe\u0cb0\u0cb0\u0cc1 \u0c8e\u0c9a\u0ccd\u0c9a\u0cb0\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0cbe\u0cb0\u0cc6.",15),A.aM("\u092f\u0938\u094d\u092e\u093f\u0928\u094d \u092e\u093e\u0938\u0947 \u0928 \u0938\u0902\u0915\u094d\u0930\u093e\u0928\u094d\u0924\u093f\u0903 \u0938\u0902\u0915\u094d\u0930\u093e\u0928\u094d\u0924\u093f\u0926\u094d\u0935\u092f\u092e\u0947\u0935 \u0935\u093e \u0964\n\u092e\u0932\u092e\u093e\u0938\u0903 \u0938 \u0935\u093f\u091c\u094d\u091e\u0947\u092f\u094b \u0935\u0930\u094d\u091c\u094d\u092f\u0903 \u0938\u094d\u092f\u093e\u0924\u094d \u0938\u0930\u094d\u0935\u0915\u0930\u094d\u092e\u0938\u0941 \u0965 \u0967\u096c \u0965","mc_1_16",'\u0caf\u0cbe\u0cb5 \u0c9a\u0cbe\u0c82\u0ca6\u0ccd\u0cb0\u0cae\u0cbe\u0ca8 \u0ca4\u0cbf\u0c82\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8 \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cae\u0ca3 (\u0cb0\u0cbe\u0cb6\u0cbf \u0cac\u0ca6\u0cb2\u0cbe\u0cb5\u0ca3\u0cc6) \u0c87\u0cb0\u0cc1\u0cb5\u0cc1\u0ca6\u0cbf\u0cb2\u0ccd\u0cb2\u0cb5\u0ccb, \u0c85\u0ca5\u0cb5\u0cbe \u0c92\u0c82\u0ca6\u0cc7 \u0ca4\u0cbf\u0c82\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8 \u0c8e\u0cb0\u0ca1\u0cc1 \u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cae\u0ca3\u0c97\u0cb3\u0cc1 \u0cac\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6\u0caf\u0ccb, \u0c85\u0ca6\u0ca8\u0ccd\u0ca8\u0cc1 "\u0cae\u0cb2\u0cae\u0cbe\u0cb8" \u0c85\u0ca5\u0cb5\u0cbe "\u0c95\u0ccd\u0cb7\u0caf\u0cae\u0cbe\u0cb8" \u0c8e\u0c82\u0ca6\u0cc1 \u0ca4\u0cbf\u0cb3\u0cbf\u0caf\u0cac\u0cc7\u0c95\u0cc1. \u0c87\u0ca6\u0cc1 \u0c8e\u0cb2\u0ccd\u0cb2\u0cbe \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cbf\u0c97\u0cc2 \u0cb5\u0cb0\u0ccd\u0c9c\u0ccd\u0caf.',"\u0caf\u0cb8\u0ccd\u0cae\u0cbf\u0ca8\u0ccd \u0cae\u0cbe\u0cb8\u0cc7 \u0ca8 \u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cbe\u0c82\u0ca4\u0cbf\u0c83 \u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cbe\u0c82\u0ca4\u0cbf\u0ca6\u0ccd\u0cb5\u0caf\u0cae\u0cc7\u0cb5 \u0cb5\u0cbe \u0964\n\u0cae\u0cb2\u0cae\u0cbe\u0cb8\u0c83 \u0cb8 \u0cb5\u0cbf\u0c9c\u0ccd\u0c9e\u0cc7\u0caf\u0ccb \u0cb5\u0cb0\u0ccd\u0c9c\u0ccd\u0caf\u0c83 \u0cb8\u0ccd\u0caf\u0cbe\u0ca4\u0ccd \u0cb8\u0cb0\u0ccd\u0cb5\u0c95\u0cb0\u0ccd\u0cae\u0cb8\u0cc1 \u0965 \u0ce7\u0cec \u0965",'\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0c86\u0cb3\u0cb5\u0cbe\u0ca6 \u0c95\u0cbe\u0cb2-\u0c97\u0ca3\u0cbf\u0ca4): \u0c87\u0ca6\u0cc1 \u0cb5\u0cc7\u0ca6\u0c97\u0cb3 \u0c8b\u0ca4\u0cc1\u0c97\u0cb3 \u0cb8\u0cae\u0ca4\u0ccb\u0cb2\u0ca8\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c95\u0cbe\u0caf\u0ccd\u0ca6\u0cc1\u0c95\u0cca\u0cb3\u0ccd\u0cb3\u0cc1\u0cb5 \u0c95\u0ccd\u0caf\u0cbe\u0cb2\u0cc6\u0c82\u0ca1\u0cb0\u0ccd \u0cb0\u0cb9\u0cb8\u0ccd\u0caf. \u0cb8\u0cc2\u0cb0\u0ccd\u0caf \u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cae\u0ca3\u0cb5\u0cc7 \u0c87\u0cb2\u0ccd\u0cb2\u0ca6 \u0c9a\u0cbe\u0c82\u0ca6\u0ccd\u0cb0\u0cae\u0cbe\u0cb8\u0cb5\u0cc1 \u0caa\u0ccd\u0cb0\u0cbe\u0ca3\u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0caf (\u0cb8\u0ccc\u0cb0\u0cb6\u0c95\u0ccd\u0ca4\u0cbf) \u0c95\u0cca\u0cb0\u0ca4\u0cc6\u0caf\u0cbf\u0c82\u0ca6 "\u0c85\u0ca7\u0cbf\u0c95\u0cae\u0cbe\u0cb8" (\u0caa\u0cc1\u0cb0\u0cc1\u0cb7\u0ccb\u0ca4\u0ccd\u0ca4\u0cae \u0cae\u0cbe\u0cb8) \u0c86\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c86\u0ca6\u0cb0\u0cc6 \u0c92\u0c82\u0ca6\u0cc7 \u0c9a\u0cbe\u0c82\u0ca6\u0ccd\u0cb0\u0cae\u0cbe\u0cb8\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cb8\u0cc2\u0cb0\u0ccd\u0caf \u0c8e\u0cb0\u0ca1\u0cc1 \u0cac\u0cbe\u0cb0\u0cbf \u0cb0\u0cbe\u0cb6\u0cbf \u0cac\u0ca6\u0cb2\u0cbe\u0caf\u0cbf\u0cb8\u0cbf\u0ca6\u0cb0\u0cc6 \u0c85\u0ca6\u0cc1 \u0cb6\u0cc1\u0ca6\u0ccd\u0ca7 \u0cb6\u0cc2\u0ca8\u0ccd\u0caf\u0cb5\u0cbe\u0ca6 "\u0c95\u0ccd\u0cb7\u0caf\u0cae\u0cbe\u0cb8"\u0cb5\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c85\u0ca7\u0cbf\u0c95\u0cae\u0cbe\u0cb8\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0c9c\u0caa, \u0ca6\u0cbe\u0ca8, \u0c89\u0caa\u0cb5\u0cbe\u0cb8\u0c97\u0cb3\u0cbf\u0c97\u0cc6 (\u0ca8\u0cbf\u0ca4\u0ccd\u0caf \u0ca8\u0cc8\u0cae\u0cbf\u0ca4\u0ccd\u0ca4\u0cbf\u0c95 \u0c95\u0cb0\u0ccd\u0cae) \u0c85\u0ca4\u0cbf \u0cb9\u0cc6\u0c9a\u0ccd\u0c9a\u0cc1 \u0c85\u0ca7\u0ccd\u0caf\u0cbe\u0ca4\u0ccd\u0cae\u0cbf\u0c95 \u0cac\u0cb2\u0cb5\u0cbf\u0ca6\u0ccd\u0ca6\u0cb0\u0cc2, \u0cb2\u0ccc\u0c95\u0cbf\u0c95 \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cbe\u0ca6 \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9, \u0cae\u0cc1\u0c82\u0c9c\u0cbf, \u0c97\u0cc3\u0cb9\u0caa\u0ccd\u0cb0\u0cb5\u0cc7\u0cb6\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0c87\u0ca6\u0cc1 \u0cae\u0cb2-\u0cb8\u0cae\u0cbe\u0ca8 (\u0ca4\u0ccd\u0caf\u0cbe\u0c9c\u0ccd\u0caf) \u0c8e\u0c82\u0ca6\u0cc1 \u0caa\u0cc0\u0caf\u0cc2\u0cb7\u0ca7\u0cbe\u0cb0\u0cbe \u0cb5\u0cbf\u0cb5\u0cb0\u0cbf\u0cb8\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6.',16),A.aM("\u0938\u0942\u0930\u094d\u092f\u0917\u094d\u0930\u0939\u0947 \u0924\u0941 \u0938\u092a\u094d\u0924\u093e\u0939\u092e\u0937\u094d\u091f\u093e\u0939\u0902 \u0936\u0936\u093f\u0928\u094b\u0917\u094d\u0930\u0939\u0947 \u0964\n\u091a\u0942\u0921\u094b\u092a\u0928\u092f\u0928\u094b\u0926\u094d\u0935\u093e\u0939\u092e\u0939\u093e\u0926\u093e\u0928\u093e\u0928\u093f \u0935\u0930\u094d\u091c\u092f\u0947\u0924\u094d \u0965 \u0967\u096d \u0965","mc_1_17","\u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0c97\u0ccd\u0cb0\u0cb9\u0ca3\u0cb5\u0cbe\u0ca6\u0cbe\u0c97 \u0c8f\u0cb3\u0cc1 \u0cb0\u0cbe\u0ca4\u0ccd\u0cb0\u0cbf\u0c97\u0cb3\u0cc1 \u0cb9\u0cbe\u0c97\u0cc2 \u0c9a\u0c82\u0ca6\u0ccd\u0cb0\u0c97\u0ccd\u0cb0\u0cb9\u0ca3\u0cb5\u0cbe\u0ca6\u0cbe\u0c97 \u0c8e\u0c82\u0c9f\u0cc1 \u0cb0\u0cbe\u0ca4\u0ccd\u0cb0\u0cbf\u0c97\u0cb3 \u0cb5\u0cb0\u0cc6\u0c97\u0cc6 \u0c9a\u0ccc\u0cb2 (\u0c9a\u0cc2\u0ca1\u0cbe\u0c95\u0cb0\u0ccd\u0cae), \u0c89\u0caa\u0ca8\u0caf\u0ca8 (\u0cae\u0cc1\u0c82\u0c9c\u0cbf), \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cae\u0cb9\u0cbe\u0ca6\u0cbe\u0ca8\u0c97\u0cb3\u0c82\u0ca4\u0cb9 \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cac\u0cbe\u0cb0\u0ca6\u0cc1.","\u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0c97\u0ccd\u0cb0\u0cb9\u0cc7 \u0ca4\u0cc1 \u0cb8\u0caa\u0ccd\u0ca4\u0cbe\u0cb9\u0cae\u0cb7\u0ccd\u0c9f\u0cbe\u0cb9\u0c82 \u0cb6\u0cb6\u0cbf\u0ca8\u0ccb\u0c97\u0ccd\u0cb0\u0cb9\u0cc7 \u0964\n\u0c9a\u0cc2\u0ca1\u0ccb\u0caa\u0ca8\u0caf\u0ca8\u0ccb\u0ca6\u0ccd\u0cb5\u0cbe\u0cb9\u0cae\u0cb9\u0cbe\u0ca6\u0cbe\u0ca8\u0cbe\u0ca8\u0cbf \u0cb5\u0cb0\u0ccd\u0c9c\u0caf\u0cc7\u0ca4\u0ccd \u0965 \u0ce7\u0ced \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0c97\u0ccd\u0cb0\u0cb9\u0ca3 \u0ca6\u0ccb\u0cb7\u0ca6 \u0cb5\u0cbf\u0c9c\u0ccd\u0c9e\u0cbe\u0ca8): \u0c97\u0ccd\u0cb0\u0cb9\u0ca3\u0c97\u0cb3\u0cc1 \u0cad\u0cc2\u0cae\u0cbf\u0caf \u0cae\u0cc7\u0cb2\u0cbf\u0ca8 \u0c95\u0cbe\u0c82\u0ca4\u0cc0\u0caf \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c9c\u0cc8\u0cb5\u0cbf\u0c95 \u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0caf\u0cb2\u0ccd\u0cb2\u0cbf \u0ca4\u0cc0\u0cb5\u0ccd\u0cb0 \u0c8f\u0cb0\u0cc1\u0caa\u0cc7\u0cb0\u0cc1\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0c89\u0c82\u0c9f\u0cc1\u0cae\u0cbe\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6. \u0c9a\u0c82\u0ca6\u0ccd\u0cb0\u0ca8\u0cc1 \u0cae\u0ca8\u0cb8\u0ccd\u0cb8\u0cbf\u0c97\u0cc6 \u0c92\u0ca1\u0cc6\u0caf (\u0cae\u0ca8\u0cb8\u0ccb \u0c9c\u0cbe\u0ca4\u0c83) \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8\u0cc1 \u0c86\u0ca4\u0ccd\u0cae\u0c95\u0ccd\u0c95\u0cc6 \u0c92\u0ca1\u0cc6\u0caf. \u0c87\u0cb5\u0cb0\u0cc1 \u0cb0\u0cbe\u0cb9\u0cc1-\u0c95\u0cc7\u0ca4\u0cc1\u0c97\u0cb3\u0cbf\u0c82\u0ca6 \u0caa\u0cc0\u0ca1\u0cbf\u0ca4\u0cb0\u0cbe\u0ca6\u0cbe\u0c97 \u0c85\u0ca6\u0cb0 \u0cb8\u0cc2\u0ca4\u0c95\u0ca6 (\u0c85\u0cb6\u0cc1\u0ca6\u0ccd\u0ca7) \u0caa\u0ccd\u0cb0\u0cad\u0cbe\u0cb5 \u0cb5\u0cbe\u0ca4\u0cbe\u0cb5\u0cb0\u0ca3\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cb9\u0cb2\u0cb5\u0cc1 \u0ca6\u0cbf\u0ca8\u0c97\u0cb3\u0cb5\u0cb0\u0cc6\u0c97\u0cc6 \u0c89\u0cb3\u0cbf\u0caf\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c85\u0ca6\u0c95\u0ccd\u0c95\u0cbe\u0c97\u0cbf\u0caf\u0cc7 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0c97\u0ccd\u0cb0\u0cb9\u0ca3\u0ca6 \u0ca8\u0c82\u0ca4\u0cb0 \u0c8f\u0cb3\u0cc1 \u0ca6\u0cbf\u0ca8 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c9a\u0c82\u0ca6\u0ccd\u0cb0\u0c97\u0ccd\u0cb0\u0cb9\u0ca3\u0ca6 \u0ca8\u0c82\u0ca4\u0cb0 \u0c8e\u0c82\u0c9f\u0cc1 \u0ca6\u0cbf\u0ca8\u0c97\u0cb3 \u0c95\u0cbe\u0cb2 \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0cb6\u0cbe\u0cb6\u0ccd\u0cb5\u0ca4 \u0cac\u0c82\u0ca7\u0c97\u0cb3 (\u0cb5\u0cbf\u0cb5\u0cbe\u0cb9) \u0c85\u0ca5\u0cb5\u0cbe \u0cb6\u0c95\u0ccd\u0ca4\u0cbf-\u0caa\u0cb0\u0cbf\u0cb5\u0cb0\u0ccd\u0ca4\u0ca8\u0cbe (\u0c89\u0caa\u0ca8\u0caf\u0ca8) \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb8\u0c82\u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cb5\u0cbe\u0c97\u0cbf \u0ca8\u0cbf\u0cb0\u0ccd\u0cac\u0c82\u0ca7\u0cbf\u0cb8\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6.",17),A.aM("\u0935\u094d\u092f\u0924\u0940\u092a\u093e\u0924\u094b \u0935\u0948\u0927\u0943\u0924\u093f\u0936\u094d\u091a \u0938\u0930\u094d\u0935\u0915\u093e\u0930\u094d\u092f\u0947\u0937\u0941 \u0917\u0930\u094d\u0939\u093f\u0924\u094c \u0964\n\u0924\u092f\u094b\u0930\u0928\u094d\u0924\u0947 \u091a \u0915\u0930\u094d\u0924\u0935\u094d\u092f\u0902 \u0936\u0941\u092d\u0902 \u0938\u0930\u094d\u0935\u0902 \u092a\u094d\u0930\u092f\u0924\u094d\u0928\u0924\u0903 \u0965 \u0967\u096e \u0965","mc_1_18","'\u0cb5\u0ccd\u0caf\u0ca4\u0cc0\u0caa\u0cbe\u0ca4' \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 '\u0cb5\u0cc8\u0ca7\u0cc3\u0ca4\u0cbf' \u0c8e\u0c82\u0cac\u0cc6\u0cb0\u0ca1\u0cc1 \u0ca8\u0cbf\u0ca4\u0ccd\u0caf-\u0caf\u0ccb\u0c97\u0c97\u0cb3\u0cc1 \u0c8e\u0cb2\u0ccd\u0cb2\u0cbe \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cbf\u0c97\u0cc2 \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0ca8\u0cbf\u0c82\u0ca6\u0ca8\u0cc0\u0caf\u0cb5\u0cbe\u0c97\u0cbf\u0cb5\u0cc6 (\u0cb5\u0cb0\u0ccd\u0c9c\u0ccd\u0caf). \u0c88 \u0c8e\u0cb0\u0ca1\u0cc1 \u0caf\u0ccb\u0c97\u0c97\u0cb3\u0cc1 \u0cb8\u0c82\u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cb5\u0cbe\u0c97\u0cbf \u0cae\u0cc1\u0c97\u0cbf\u0ca6 \u0cae\u0cc7\u0cb2\u0cc6\u0caf\u0cc7 \u0caa\u0ccd\u0cb0\u0caf\u0ca4\u0ccd\u0ca8\u0caa\u0cc2\u0cb0\u0ccd\u0cb5\u0c95\u0cb5\u0cbe\u0c97\u0cbf \u0cb6\u0cc1\u0cad\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cac\u0cc7\u0c95\u0cc1.","\u0cb5\u0ccd\u0caf\u0ca4\u0cc0\u0caa\u0cbe\u0ca4\u0ccb \u0cb5\u0cc8\u0ca7\u0cc3\u0ca4\u0cbf\u0cb6\u0ccd\u0c9a \u0cb8\u0cb0\u0ccd\u0cb5\u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0cc7\u0cb7\u0cc1 \u0c97\u0cb0\u0ccd\u0cb9\u0cbf\u0ca4\u0ccc \u0964\n\u0ca4\u0caf\u0ccb\u0cb0\u0c82\u0ca4\u0cc7 \u0c9a \u0c95\u0cb0\u0ccd\u0ca4\u0cb5\u0ccd\u0caf\u0c82 \u0cb6\u0cc1\u0cad\u0c82 \u0cb8\u0cb0\u0ccd\u0cb5\u0c82 \u0caa\u0ccd\u0cb0\u0caf\u0ca4\u0ccd\u0ca8\u0ca4\u0c83 \u0965 \u0ce7\u0cee \u0965",'\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0c96\u0c97\u0ccb\u0cb3 \u0cb0\u0cb9\u0cb8\u0ccd\u0caf): \u0caa\u0ccd\u0cb0\u0ca4\u0cbf\u0ca6\u0cbf\u0ca8 \u0cb8\u0cc2\u0cb0\u0ccd\u0caf \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0c9a\u0c82\u0ca6\u0ccd\u0cb0\u0cb0 \u0ca8\u0cbf\u0cb0\u0ccd\u0ca6\u0cbf\u0cb7\u0ccd\u0c9f \u0c95\u0ccb\u0ca8\u0cae\u0cbe\u0ca8\u0c97\u0cb3\u0cbf\u0c82\u0ca6 \u0ce8\u0ced \u0ca8\u0cbf\u0ca4\u0ccd\u0caf-\u0caf\u0ccb\u0c97\u0c97\u0cb3\u0cc1 \u0c89\u0c82\u0c9f\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6. \u0c87\u0ca6\u0cb0\u0cb2\u0ccd\u0cb2\u0cbf \u0cb5\u0ccd\u0caf\u0ca4\u0cc0\u0caa\u0cbe\u0ca4 (\u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0cb5\u0cc7\u0c97\u0ca6 \u0caa\u0ca4\u0ca8) \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb5\u0cc8\u0ca7\u0cc3\u0ca4\u0cbf (\u0cac\u0cc6\u0c82\u0cac\u0cb2\u0cb5\u0cbf\u0cb2\u0ccd\u0cb2\u0ca6 \u0cb8\u0ccd\u0ca5\u0cbf\u0ca4\u0cbf) \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0cb5\u0cbf\u0ca8\u0cbe\u0cb6\u0c95\u0cbe\u0cb0\u0cbf\u0caf\u0cbe\u0c97\u0cbf\u0cb5\u0cc6. \u0c88 \u0caf\u0ccb\u0c97\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0cb5\u0cb8\u0ccd\u0ca4\u0cc1\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c96\u0cb0\u0cc0\u0ca6\u0cbf\u0cb8\u0cbf\u0ca6\u0cb0\u0cc2 \u0c85\u0ca6\u0cc1 \u0cb9\u0cbe\u0ca8\u0cbf\u0caf\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6, \u0caf\u0cbe\u0cb5\u0cc1\u0ca6\u0cc7 \u0cb5\u0ccd\u0caf\u0cb5\u0cb9\u0cbe\u0cb0 \u0cae\u0cbe\u0ca1\u0cbf\u0ca6\u0cb0\u0cc2 \u0c85\u0ca6\u0cc1 "\u0caa\u0ca4\u0ca8" (fall) \u0c86\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c87\u0cb5\u0cc6\u0cb0\u0ca1\u0cc1 \u0caf\u0ccb\u0c97\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0c8e\u0cb7\u0ccd\u0c9f\u0cb0 \u0cae\u0c9f\u0ccd\u0c9f\u0cbf\u0c97\u0cc6 \u0cb5\u0cbf\u0cb0\u0ccb\u0ca7\u0cbf\u0cb8\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6 \u0c8e\u0c82\u0ca6\u0cb0\u0cc6, "\u0c97\u0cc1\u0cb0\u0cc1\u0cac\u0cb2" \u0c85\u0ca5\u0cb5\u0cbe "\u0cb8\u0cbf\u0ca6\u0ccd\u0ca7\u0cbf\u0caf\u0ccb\u0c97" \u0c87\u0ca6\u0ccd\u0ca6\u0cb0\u0cc2 \u0cb8\u0cb9 \u0cb5\u0cc8\u0ca7\u0cc3\u0ca4\u0cbf-\u0cb5\u0ccd\u0caf\u0ca4\u0cc0\u0caa\u0cbe\u0ca4\u0c97\u0cb3\u0cbf\u0ca6\u0ccd\u0ca6\u0cb0\u0cc6 \u0ca8\u0cbf\u0cb0\u0ccd\u0ca6\u0cbf\u0cb7\u0ccd\u0c9f \u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0c95\u0ca1\u0ccd\u0ca1\u0cbe\u0caf\u0cb5\u0cbe\u0c97\u0cbf \u0ca4\u0cbf\u0cb0\u0cb8\u0ccd\u0c95\u0cb0\u0cbf\u0cb8\u0cb2\u0cc7\u0cac\u0cc7\u0c95\u0cc1.',18),A.aM("\u091c\u0928\u094d\u092e\u0930\u094d\u0915\u094d\u0937\u0947 \u091c\u0928\u094d\u092e\u0932\u0917\u094d\u0928\u0947 \u091a \u091c\u0928\u094d\u092e\u092e\u093e\u0938\u0947 \u0924\u0925\u0948\u0935 \u091a \u0964\n\u091a\u0942\u0921\u094b\u092a\u0928\u092f\u0928\u094b\u0926\u094d\u0935\u093e\u0939\u092e\u0939\u093e\u0926\u093e\u0928\u093e\u0928\u093f \u0935\u0930\u094d\u091c\u092f\u0947\u0924\u094d \u0965 \u0967\u096f \u0965","mc_1_19","\u0cae\u0ca8\u0cc1\u0cb7\u0ccd\u0caf\u0ca8\u0cc1 \u0ca4\u0cbe\u0ca8\u0cc1 \u0cb9\u0cc1\u0c9f\u0ccd\u0c9f\u0cbf\u0ca6 \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf, \u0ca4\u0cbe\u0ca8\u0cc1 \u0c9c\u0ca8\u0cbf\u0cb8\u0cbf\u0ca6 \u0cb2\u0c97\u0ccd\u0ca8\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf, \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0ca4\u0cbe\u0ca8\u0cc1 \u0c9c\u0ca8\u0cbf\u0cb8\u0cbf\u0ca6 \u0c9a\u0cbe\u0c82\u0ca6\u0ccd\u0cb0\u0cae\u0cbe\u0ca8 \u0ca4\u0cbf\u0c82\u0c97\u0cb3\u0cb2\u0ccd\u0cb2\u0cbf (\u0c9c\u0ca8\u0ccd\u0cae\u0cae\u0cbe\u0cb8) \u0c9a\u0ccc\u0cb2, \u0c89\u0caa\u0ca8\u0caf\u0ca8, \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cae\u0cb9\u0cbe\u0ca6\u0cbe\u0ca8\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cac\u0cbe\u0cb0\u0ca6\u0cc1.","\u0c9c\u0ca8\u0ccd\u0cae\u0cb0\u0ccd\u0c95\u0ccd\u0cb7\u0cc7 \u0c9c\u0ca8\u0ccd\u0cae\u0cb2\u0c97\u0ccd\u0ca8\u0cc7 \u0c9a \u0c9c\u0ca8\u0ccd\u0cae\u0cae\u0cbe\u0cb8\u0cc7 \u0ca4\u0ca5\u0cc8\u0cb5 \u0c9a \u0964\n\u0c9a\u0cc2\u0ca1\u0ccb\u0caa\u0ca8\u0caf\u0ca8\u0ccb\u0ca6\u0ccd\u0cb5\u0cbe\u0cb9\u0cae\u0cb9\u0cbe\u0ca6\u0cbe\u0ca8\u0cbe\u0ca8\u0cbf \u0cb5\u0cb0\u0ccd\u0c9c\u0caf\u0cc7\u0ca4\u0ccd \u0965 \u0ce7\u0cef \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0c9c\u0ca8\u0ccd\u0cae \u0c95\u0cbe\u0cb2\u0ca6 \u0ca6\u0ccb\u0cb7): \u0c87\u0ca6\u0cc1 \u0cb5\u0cc8\u0caf\u0c95\u0ccd\u0ca4\u0cbf\u0c95 \u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4 \u0cb5\u0cbf\u0c9c\u0ccd\u0c9e\u0cbe\u0ca8\u0ca6 \u0c85\u0ca1\u0cbf\u0caa\u0cbe\u0caf. \u0cae\u0ca8\u0cc1\u0cb7\u0ccd\u0caf\u0ca8 \u0c9c\u0ca8\u0ccd\u0cae \u0ca8\u0c95\u0ccd\u0cb7\u0ca4\u0ccd\u0cb0, \u0cb2\u0c97\u0ccd\u0ca8 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cae\u0cbe\u0cb8\u0c97\u0cb3\u0cc1 \u0c85\u0cb5\u0ca8 \u0cb6\u0cbe\u0cb0\u0cc0\u0cb0\u0cbf\u0c95 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cae\u0cbe\u0ca8\u0cb8\u0cbf\u0c95 \u0cb0\u0c9a\u0ca8\u0cc6\u0c97\u0cc6 (DNA \u0c97\u0cc6 \u0cb8\u0cae\u0cbe\u0ca8\u0cb5\u0cbe\u0c97\u0cbf) \u0c95\u0cbe\u0cb0\u0ca3\u0cb5\u0cbe\u0c97\u0cbf\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6. \u0c85\u0ca6\u0cc7 \u0caa\u0c82\u0c9a\u0cbe\u0c82\u0c97\u0ca6 \u0cb8\u0cae\u0caf\u0c97\u0cb3\u0cc1 \u0cae\u0ca4\u0ccd\u0ca4\u0cc6 \u0cae\u0cb0\u0cc1\u0c95\u0cb3\u0cbf\u0cb8\u0cbf\u0ca6\u0cbe\u0c97, \u0caa\u0ccd\u0cb0\u0c95\u0cc3\u0ca4\u0cbf\u0caf \u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0caf\u0cc1 \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0c89\u0ca4\u0ccd\u0ca4\u0cc1\u0c82\u0c97\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb8\u0cc2\u0c95\u0ccd\u0cb7\u0ccd\u0cae\u0cb5\u0cbe\u0c97\u0cbf\u0cb0\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c86 \u0cb8\u0cae\u0caf\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9 \u0c85\u0ca5\u0cb5\u0cbe \u0cae\u0cc1\u0c82\u0c9c\u0cbf\u0caf\u0c82\u0ca4\u0cb9 \u0c85\u0ca4\u0cbf \u0cb9\u0cc6\u0c9a\u0ccd\u0c9a\u0cc1 \u0c92\u0ca4\u0ccd\u0ca4\u0ca1\u0ca6 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cb0\u0cc2\u0caa\u0cbe\u0c82\u0ca4\u0cb0\u0ca6 (Transformative) \u0caf\u0c9c\u0ccd\u0c9e-\u0c95\u0cb0\u0ccd\u0cae\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cbf\u0ca6\u0cb0\u0cc6 \u0ca6\u0cc7\u0cb9 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cae\u0ca8\u0cb8\u0ccd\u0cb8\u0cc1 \u0c86 \u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0caf\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca4\u0ca1\u0cc6\u0ca6\u0cc1\u0c95\u0cca\u0cb3\u0ccd\u0cb3\u0cb2\u0cbe\u0cb0\u0ca6\u0cc6 \u0c86\u0c98\u0cbe\u0ca4\u0c95\u0ccd\u0c95\u0cca\u0cb3\u0c97\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6 (\u0caa\u0ca4\u0ca8 \u0c85\u0ca5\u0cb5\u0cbe \u0c95\u0cbe\u0caf\u0cbf\u0cb2\u0cc6) \u0c8e\u0c82\u0cac\u0cc1\u0ca6\u0cc1 \u0c9c\u0ccd\u0caf\u0ccb\u0ca4\u0cbf\u0cb7 \u0cb6\u0cbe\u0cb8\u0ccd\u0ca4\u0ccd\u0cb0\u0ca6 \u0c97\u0c82\u0cad\u0cc0\u0cb0 \u0c8e\u0c9a\u0ccd\u0c9a\u0cb0\u0cbf\u0c95\u0cc6.",19),A.aM("\u0938\u0902\u0915\u094d\u0930\u093e\u0928\u094d\u0924\u094c \u092a\u0942\u0930\u094d\u0935\u0924\u0936\u094d\u091a\u094b\u0930\u094d\u0927\u094d\u0935\u0902 \u0928\u093e\u0921\u094d\u092f\u0903 \u0937\u094b\u0921\u0936 \u0937\u094b\u0921\u0936 \u0964\n\u092a\u0941\u0923\u094d\u092f\u0915\u093e\u0932\u094b\u093d\u092f\u092e\u0941\u0926\u094d\u0926\u093f\u0937\u094d\u091f\u0903 \u0936\u0941\u092d\u0915\u0930\u094d\u092e\u0938\u0941 \u0935\u0930\u094d\u091c\u093f\u0924\u0903 \u0965 \u0968\u0966 \u0965","mc_1_20",'\u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8\u0cc1 \u0c92\u0c82\u0ca6\u0cc1 \u0cb0\u0cbe\u0cb6\u0cbf\u0caf\u0cbf\u0c82\u0ca6 \u0cae\u0ca4\u0ccd\u0ca4\u0cca\u0c82\u0ca6\u0cc1 \u0cb0\u0cbe\u0cb6\u0cbf\u0c97\u0cc6 \u0c95\u0cbe\u0cb2\u0cbf\u0ca1\u0cc1\u0cb5 "\u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cae\u0ca3" \u0c95\u0cbe\u0cb2\u0ca6 \u0cae\u0cca\u0ca6\u0cb2\u0cc1 \u0ce7\u0cec \u0c97\u0cb3\u0cbf\u0c97\u0cc6\u0c97\u0cb3\u0cc1 (\u0cec.\u0cea \u0c97\u0c82\u0c9f\u0cc6) \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0ca8\u0c82\u0ca4\u0cb0\u0ca6 \u0ce7\u0cec \u0c97\u0cb3\u0cbf\u0c97\u0cc6\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 "\u0caa\u0cc1\u0ca3\u0ccd\u0caf\u0c95\u0cbe\u0cb2" \u0c8e\u0ca8\u0ccd\u0ca8\u0cc1\u0ca4\u0ccd\u0ca4\u0cbe\u0cb0\u0cc6. \u0c88 \u0c95\u0cbe\u0cb2\u0cb5\u0cc1 \u0cb8\u0ccd\u0ca8\u0cbe\u0ca8-\u0c9c\u0caa\u0cbe\u0ca6\u0cbf\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0c85\u0ca4\u0ccd\u0caf\u0c82\u0ca4 \u0cb6\u0ccd\u0cb0\u0cc7\u0cb7\u0ccd\u0ca0\u0cb5\u0cbe\u0ca6\u0cb0\u0cc2, \u0cb2\u0ccc\u0c95\u0cbf\u0c95 \u0cb6\u0cc1\u0cad\u0c95\u0cb0\u0ccd\u0cae\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0cb5\u0cb0\u0ccd\u0c9c\u0ccd\u0caf\u0cb5\u0cbe\u0c97\u0cbf\u0ca6\u0cc6.',"\u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cbe\u0c82\u0ca4\u0ccc \u0caa\u0cc2\u0cb0\u0ccd\u0cb5\u0ca4\u0cb6\u0ccd\u0c9a\u0ccb\u0cb0\u0ccd\u0ca7\u0ccd\u0cb5\u0c82 \u0ca8\u0cbe\u0ca1\u0ccd\u0caf\u0c83 \u0cb7\u0ccb\u0ca1\u0cb6 \u0cb7\u0ccb\u0ca1\u0cb6 \u0964\n\u0caa\u0cc1\u0ca3\u0ccd\u0caf\u0c95\u0cbe\u0cb2\u0ccb\u0cbd\u0caf\u0cae\u0cc1\u0ca6\u0ccd\u0ca6\u0cbf\u0cb7\u0ccd\u0c9f\u0c83 \u0cb6\u0cc1\u0cad\u0c95\u0cb0\u0ccd\u0cae\u0cb8\u0cc1 \u0cb5\u0cb0\u0ccd\u0c9c\u0cbf\u0ca4\u0c83 \u0965 \u0ce8\u0ce6 \u0965","\u0cb5\u0ccd\u0caf\u0cbe\u0c96\u0ccd\u0caf\u0cbe\u0ca8 (\u0cb8\u0cc2\u0cb0\u0ccd\u0caf \u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cae\u0ca3\u0ca6 \u0cb0\u0cb9\u0cb8\u0ccd\u0caf): \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8\u0cc1 \u0cb0\u0cbe\u0cb6\u0cbf\u0c9a\u0c95\u0ccd\u0cb0\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca6\u0cbe\u0c9f\u0cc1\u0cb5\u0cbe\u0c97 \u0c89\u0c82\u0c9f\u0cbe\u0c97\u0cc1\u0cb5 \u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cae\u0ca3\u0cb5\u0cc1 (\u0c89\u0ca6\u0cbe: \u0cae\u0c95\u0cb0 \u0cb8\u0c82\u0c95\u0ccd\u0cb0\u0cbe\u0c82\u0ca4\u0cbf) \u0ca6\u0cca\u0ca1\u0ccd\u0ca1 \u0c9c\u0ccd\u0caf\u0ccb\u0ca4\u0cbf\u0cb7\u0ccd\u0caf \u0cb5\u0cbf\u0ca6\u0ccd\u0caf\u0cae\u0cbe\u0ca8. \u0cb8\u0cc2\u0cb0\u0ccd\u0caf\u0ca8 \u0caa\u0ccd\u0cb0\u0cb5\u0cc7\u0cb6\u0ca6 \u0cb9\u0cbf\u0c82\u0ca6\u0cbf\u0ca8 \u0cae\u0ca4\u0ccd\u0ca4\u0cc1 \u0cae\u0cc1\u0c82\u0ca6\u0cbf\u0ca8 \u0cec.\u0cea \u0c97\u0c82\u0c9f\u0cc6\u0c97\u0cb3 \u0c95\u0cbe\u0cb2 \u0cad\u0cc2\u0cae\u0cbf\u0caf \u0c95\u0cbe\u0c82\u0ca4\u0c95\u0ccd\u0cb7\u0cc7\u0ca4\u0ccd\u0cb0\u0cb5\u0cc1 \u0cad\u0cbe\u0cb0\u0cbf \u0caa\u0cb0\u0cbf\u0cb5\u0cb0\u0ccd\u0ca4\u0ca8\u0cc6\u0c97\u0cc6 \u0c92\u0cb3\u0caa\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c87\u0ca6\u0ca8\u0ccd\u0ca8\u0cc1 '\u0caa\u0cc1\u0ca3\u0ccd\u0caf\u0c95\u0cbe\u0cb2' \u0c8e\u0c82\u0ca6\u0cc1 \u0c95\u0cb0\u0cc6\u0caf\u0cb2\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0ca6\u0cc6. \u0c88 \u0cb8\u0cae\u0caf\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0ca8\u0ca6\u0cbf\u0cb8\u0ccd\u0ca8\u0cbe\u0ca8, \u0caa\u0cbf\u0c82\u0ca1\u0caa\u0ccd\u0cb0\u0ca6\u0cbe\u0ca8, \u0cb9\u0ccb\u0cae-\u0cb9\u0cb5\u0ca8, \u0c9c\u0caa-\u0ca4\u0caa\u0cb8\u0ccd\u0cb8\u0cc1\u0c97\u0cb3\u0cc1 \u0cb8\u0cb9\u0cb8\u0ccd\u0cb0\u0caa\u0c9f\u0ccd\u0c9f\u0cc1 \u0cab\u0cb2 \u0c95\u0cca\u0ca1\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6. \u0c86\u0ca6\u0cb0\u0cc6, \u0c87\u0ca6\u0cc7 \u0cb8\u0cae\u0caf\u0ca6\u0cb2\u0ccd\u0cb2\u0cbf \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9, \u0c97\u0cc3\u0cb9\u0caa\u0ccd\u0cb0\u0cb5\u0cc7\u0cb6, \u0c97\u0cb0\u0ccd\u0cad\u0cbe\u0ca6\u0cbe\u0ca8\u0ca6\u0c82\u0ca4\u0cb9 \u0c90\u0cb9\u0cbf\u0c95 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cae\u0cbe\u0ca1\u0cbf\u0ca6\u0cb0\u0cc6 \u0caa\u0ccd\u0cb0\u0c95\u0cc3\u0ca4\u0cbf\u0caf \u0ca4\u0cc0\u0cb5\u0ccd\u0cb0 \u0cb6\u0c95\u0ccd\u0ca4\u0cbf\u0caf\u0cbf\u0c82\u0ca6\u0cbe\u0c97\u0cbf \u0c86 \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cc1 \u0c9b\u0cbf\u0ca6\u0ccd\u0cb0\u0cb5\u0cbe\u0c97\u0cc1\u0ca4\u0ccd\u0ca4\u0cb5\u0cc6, \u0c86\u0ca6\u0ccd\u0ca6\u0cb0\u0cbf\u0c82\u0ca6 \u0c85\u0cb5\u0cc1\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0cb8\u0c82\u0caa\u0cc2\u0cb0\u0ccd\u0ca3\u0cb5\u0cbe\u0c97\u0cbf \u0ca8\u0cbf\u0cb7\u0cc7\u0ca7\u0cbf\u0cb8\u0cb2\u0cbe\u0c97\u0cbf\u0ca6\u0cc6.",20)],A.ag("z<zD>")))],A.ag("z<uW>")),"\u0cb6\u0ccd\u0cb0\u0cc0\u0cb0\u0cbe\u0cae \u0ca6\u0cc8\u0cb5\u0c9c\u0ccd\u0c9e","\u0cb6\u0cbe\u0cb8\u0ccd\u0ca4\u0ccd\u0cb0","\u0cb6\u0ccd\u0cb0\u0cc0\u0cb0\u0cbe\u0cae \u0ca6\u0cc8\u0cb5\u0c9c\u0ccd\u0c9e\u0cb0\u0cc1 \u0cb0\u0c9a\u0cbf\u0cb8\u0cbf\u0ca6 \u0caa\u0ccd\u0cb0\u0cb8\u0cbf\u0ca6\u0ccd\u0ca7 \u0c9c\u0ccd\u0caf\u0ccb\u0ca4\u0cbf\u0cb7 \u0c97\u0ccd\u0cb0\u0c82\u0ca5. \u0cb5\u0cbf\u0cb5\u0cbe\u0cb9, \u0cb5\u0cbe\u0cb8\u0ccd\u0ca4\u0cc1, \u0caa\u0ccd\u0cb0\u0caf\u0cbe\u0ca3 \u0cae\u0cc1\u0c82\u0ca4\u0cbe\u0ca6 \u0cb6\u0cc1\u0cad \u0c95\u0cbe\u0cb0\u0ccd\u0caf\u0c97\u0cb3\u0cbf\u0c97\u0cc6 \u0cb8\u0cb0\u0cbf\u0caf\u0cbe\u0ca6 \u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4\u0cb5\u0ca8\u0ccd\u0ca8\u0cc1 \u0ca8\u0cbf\u0cb0\u0ccd\u0ca3\u0caf\u0cbf\u0cb8\u0cc1\u0cb5 \u0ca8\u0cbf\u0caf\u0cae\u0c97\u0cb3\u0ca8\u0ccd\u0ca8\u0cc1 \u0c92\u0cb3\u0c97\u0cca\u0c82\u0ca1\u0cbf\u0ca6\u0cc6.","\u092e\u0941\u0939\u0942\u0930\u094d\u0924\u091a\u093f\u0928\u094d\u0924\u093e\u092e\u0923\u093f","Muhurta Chintamani","\ud83d\udd49\ufe0f","muhurta_chintamani","\u0cae\u0cc1\u0cb9\u0cc2\u0cb0\u0ccd\u0ca4 \u0c9a\u0cbf\u0c82\u0ca4\u0cbe\u0cae\u0ca3\u0cbf",20),$.aAv()],A.ag("z<qC>")))
